/* WARNING: Script requires that SQLITE_DBCONFIG_DEFENSIVE be disabled */
PRAGMA foreign_keys=OFF;
BEGIN TRANSACTION;
CREATE TABLE articles (
    id              INTEGER PRIMARY KEY AUTOINCREMENT,
    filename        TEXT NOT NULL,          -- original filename
    scan_date       TEXT NOT NULL,          -- ISO 8601: YYYY-MM-DD

    -- Metadata (automatic or manual)
    newspaper       TEXT,                   -- e.g. "Kurier"
    article_date    TEXT,                   -- publication date of the article
    page            TEXT,                   -- page number (optional)
    headline        TEXT,                   -- article headline
    summary         TEXT,                   -- AI summary (2-3 sentences)
    category        TEXT,                   -- Politik, Kultur, Sport, Wirtschaft, ...
    tags            TEXT,                   -- JSON array: '["tag1","tag2"]'

    -- Content
    full_text       TEXT,                   -- OCR full text
    image_path      TEXT,                   -- path to WebP archive image
    thumb_path      TEXT,                   -- path to JPEG thumbnail

    -- Quality & status
    ocr_confidence  REAL,                   -- Tesseract confidence 0.0–100.0
    needs_review    INTEGER DEFAULT 0,      -- 1 = manual review required
    meta_source     TEXT DEFAULT 'auto',    -- 'auto' | 'manual' | 'partial'
    created_at      TEXT DEFAULT (datetime('now')),
    updated_at      TEXT DEFAULT (datetime('now'))
, locations TEXT, urls TEXT, article_group TEXT, page_number INTEGER, section TEXT);
PRAGMA writable_schema=ON;
    headline,
    summary,
    full_text,
    tags,
    content=''articles'',
    content_rowid=''id'',
    tokenize=''unicode61''
)');
CREATE TABLE IF NOT EXISTS 'articles_fts_data'(id INTEGER PRIMARY KEY, block BLOB);
CREATE TABLE IF NOT EXISTS 'articles_fts_idx'(segid, term, pgno, PRIMARY KEY(segid, term)) WITHOUT ROWID;
CREATE TABLE IF NOT EXISTS 'articles_fts_docsize'(id INTEGER PRIMARY KEY, sz BLOB);
CREATE TABLE IF NOT EXISTS 'articles_fts_config'(k PRIMARY KEY, v) WITHOUT ROWID;
CREATE TABLE places (
        id INTEGER PRIMARY KEY AUTOINCREMENT,
        article_id INTEGER NOT NULL REFERENCES articles(id) ON DELETE CASCADE,
        name TEXT, description TEXT, address TEXT,
        postal_code TEXT, city TEXT, country TEXT,
        phone TEXT, hours TEXT, url TEXT
    , rating TEXT);
CREATE TABLE books (
    id          INTEGER PRIMARY KEY AUTOINCREMENT,
    article_id  INTEGER NOT NULL REFERENCES articles(id) ON DELETE CASCADE,
    title       TEXT,
    author      TEXT,
    publisher   TEXT,
    year        TEXT,
    pages       TEXT,
    price       TEXT,
    isbn        TEXT,
    description TEXT
);
CREATE TABLE recipes (
    id           INTEGER PRIMARY KEY AUTOINCREMENT,
    article_id   INTEGER NOT NULL REFERENCES articles(id) ON DELETE CASCADE,
    name         TEXT,
    category     TEXT,
    servings     TEXT,
    prep_time    TEXT,
    ingredients  TEXT,   -- free-text block
    instructions TEXT    -- free-text block
);
DELETE FROM sqlite_sequence;
CREATE TRIGGER articles_ai AFTER INSERT ON articles BEGIN
    VALUES (new.id, new.headline, new.summary, new.full_text, new.tags);
END;
CREATE TRIGGER articles_au AFTER UPDATE ON articles BEGIN
    VALUES ('delete', old.id, old.headline, old.summary, old.full_text, old.tags);
    VALUES (new.id, new.headline, new.summary, new.full_text, new.tags);
END;
CREATE TRIGGER articles_ad AFTER DELETE ON articles BEGIN
    VALUES ('delete', old.id, old.headline, old.summary, old.full_text, old.tags);
END;
CREATE TRIGGER articles_updated_at AFTER UPDATE ON articles BEGIN
    UPDATE articles SET updated_at = datetime('now') WHERE id = new.id;
END;
PRAGMA writable_schema=OFF;
COMMIT;
