INSERT INTO articles VALUES(1,'at_freizeit_salzupfeffer_01.tif','2026-03-09','Kurier',NULL,NULL,'TOP Mit Kids auf dem Land','Test','Reise','["Kinder", "Lokal"]',replace('florian.holzerfäkurier.at\n\nTOP Mit Kids auf dem Land\n\nWald, Wiese, Spielplatz und gutes Essen:\nDie besten Kinder-Lokale im Grünen.\n\n1 APFELBAUER\nIdylle inmitten der Wiener Hausberge. Groß-\nartige Küche mit Produkten aus der Region,\nSpielplatz am Bach, gute Kinder-Menüs.\n\n2761 Miesenbach, Ascherstr. 15, @ 02632/8244,\nMi-Sa 11-21, So 11-20, www.apfelbauer.at\n\n2 BONKA\n\nEin Gasthaus, wie es im Buche steht, nur besser\nbekocht. Und auferdem Spielplatz, Pferde und\njede Menge grüner Wienerwald.\n\n3413 Oberkirchbach 61, @ 02242/62 90, Mi-Sa 9- 21,\nSo, Fei 9-16, www.bonka. at\n\n3 NIERSCHER\nDas Essen ist hier auf Edelheurigen-Niveau, die\nAtmosphäre urig, das Angebot für Kinder umso\nprachtvoller: Platz, Streichelzoo, Obstgarten.\n\n3400 Weidling, Hauptstr. 190, @ 02243/339 33,\nDi-Fr 15-24, Sa, So, Fei 12-24, www.nierscher.at\n\n4 STOCKERWIRT\nDer Familien-Klassiker. Spielplatz, kleines Biotop\nmit Bach, Spielzeug. Zu beachten: Kinder wollen\nnicht warten, der Andrang ist oft grofl.\n\n2392 Sulz im Wienerwald, Hauptstr. 36, @ 02238/82 590,\nMi-Sa 11.30-22, So, Fei 11-21, www.stockerwirt.com\n\n5 BLAA-ALM\nHier können sich nicht nur die Zwerge am Spiel-\nplatz mitten auf der Alm austoben, auch Eltern\nbekommen alles, was eine Hütte bieten kann.\n\n8992 Altaussee, Lichtersberg 73, @ 03622/71 102,\nMo-So 9-24, www.blaa-alm.at\n\n92\n\ndel Iikatessen florian holzer\n\nsalz & PFEFFER GASTHAUS MIRLI\n\nEin 1792 erbautes Forsthaus mit atemberaubendem\n\n‚Blick über die grünen Hügel eines außerordentlich\n\nschönen Stückerls Wienerwald, keine 15 Minuten von\nder Wiener Stadtgrenze entfernt. Gerade erst seit zehn\nJahren wird dieses Schmuckstück als Ausflugsgast-\nhaus genützt - mit Anfang des Jahres wurde das mitt-\nlerweile als „Mirli“ extrem beliebte Lokal vom früheren\nClubbing-Veranstalter Ziggy Kremser übernommen.\nDie Terrasse wurde vergrößert, der herzerwärmend\npersönliche Charme, der diesen Platz immer auszeich-\nnete, nahm aber leider ab. Die Karte ist derzeit noch\nklein, kein Problem, aber halt auch etwas beliebig, die\nSulz vom Bauernhof nebenan rustikal, der mit Wiesen-\nkräutern versehene Salat dazu eigentlich das Highlight\nder Karte (8,80 €). Der Frühlingssalat mit Ziegenkäse-\nbällchen, Spargel und Erdbeeren eine etwas fragwürdige\nKreation (10,50 €), der Schweinsbraten mit Knödel\nreichlich, aber fad (13,80 €), das Rib-Eye vom Wiener-\nwaldrind leider weder Rib-Eye, wie in der Karte, noch\nBeiried, wie auf der Rechnung erwähnt, sondern zäher\nRostbraten. Immerhin: Das Spargelgröstel mit gelben\nund violetten Kartoffeln ist dazu durchaus originell\n(19,10 €). Klar, bei Schönwetter läuft das hier von al-\nleine. Ein bisschen besser kochen wäre trotzdem fein.\n\nARAZ. Budapest\n\nDas jüngste Top-Ho-\ntel Budapests, das Continental, befindet sich im frü-\nheren Jugendstil-Bad Hungäria, sein Restaurant Araz\nhat schon viele Preise eingeheimst. Gekocht wird ei-\nne französisch-ungarische Fusionsküche.\n\nMirli, 3011 Tultner-\nbach/lIrenental,\nHeinratsberg 69,\n\n@ 0664/22231 31,\nMi-So, Fei 11.30-24,\nwww.mirli.at\n\nBEIM nachbarn\n\nAraz, HU,\nBudapest,\n\nDohäny utca 42-44,\n2+36/1/815 1100,\nMo-So 7-23,\nwww.araz.hu','\n',char(10)),'at_freizeit_salzupfeffer_01/image.webp','at_freizeit_salzupfeffer_01/thumb.jpg',92.5,0,'manual','2026-03-09 11:38:51','2026-03-10 16:15:52','["Miesenbach", "Oberkirchbach", "Weidling", "Sulz im Wienerwald", "Altaussee", "Tullnerbach"]','["www.apfelbauer.at"]',NULL,NULL,NULL);
INSERT INTO articles VALUES(2,'at_freizeit_waldviertel_01.tif','2026-03-09','KURIER.at','2023-03-17','12/13','Die Marillenblüte in der Wachau beginnt','Der Wanderblogger Stephan Schmatz gibt Tipps für eine Frühlingswanderung in der Wachau. Er zeigt fünf Wanderwege mit blühenden Marillenbäumen und beschreibt die Marilienmeile in Rossatz-Arnsdorf.','Reise','["Wanderung", "Marillen", "Wachau", "Frühling", "Wanderblogger"]',replace('Waldviertel\n\nSeite 12/13 | Freitag, 17. März 2023 | KURIER.at\n\nINN\n\nSTEPHAN SCHMATZ\n\nDie Marilienblüte in der Wachau beginnt tar sam, bei Wanderungen kann man sie am\n\nWandern, wenn die\nMarillenbäume blühen\n\nWachau. Tipps von Wanderblogger Stephan Schmatz\n\nVON ALINA GROER\n\nAm Montag ist Frühlings-\nbeginn. Die Pflanzenwelt\nerwacht schon aus dem\nWinterschlaf und in der\nWachau und im Kremstal\nsprießen bereits die Knos-\npen auf den Marillenbäu-\nmen. Eine ideale Gelegen-\nheit für eine Frühlingswan-\nderung. Stephan Schmatz\nist Wanderblogger und\nzeigt dem KURIER fünf\nWanderrouten der Region,\nbei denen man im Frühling\nviele blühende Marillen-\nbäume sehen kann.\n\n+ Spazieren für Neugierige\nDer Wachauer-Marillen-Er-\nlebnisweg ist eine gute\n\nMöglichkeit, um mehr über\nMarillen zu erfahren. Er\nbeginnt an der Dorfstraße\nin Krems-, -Angern und dau-\nert etwa eine Stunde und\nfünfundvierzig Minuten.\nDer Weg führt direkt durch\ndie Wein- und Obstgärten.\nSechs Stationen mit Info-\nTafeln und Geschichten\nvon „Lilli Marilli“ bieten\nviel Wissenswertes zur Ma-\nrille.\n\n« Zum Paradiesgarten Einen\nschönen Marillengarten\ngibt es auch beim\nStift Göttweig. Ein drei-\nstündiger Rundwander-\nweg führt von Krems-\nAngern zum Stift und wie-\nder zurück. Eine andere\n\nOption ist auch der Weg\nvon Furth zum Stift Gött-\nweig.\n\n* Die Marillenmeile Unter\ndem Namen „Marillenmei-\nle“ gibt es in Rossatz-Arns-\ndorf, Österreichs größter\nMarillenanbau-Gemeinde,\n\nsieben Wanderwege, diean\nMarillengärten und Maril-\nlenanbaubetrieben ent-\n\nlangführen.\n\n* Weg mit Ausblick Der drei-\nstündige Panoramarund-\nweg in Rossatz bietet eine\ntolle Aussicht auf die Maril-\nlengärten und den Rossatz-\nbach. Am Weg kann man\nmit Glück Smaragdeidech-\nsen bestaunen.\n\n« Abenteuer in Spitz Für den\nWassergeistweg in Spitz\nsollte man etwa zweiein-\nhalb Stunden einplanen.\nDer Weg führt durch den\nWald, über die Weinberge\nund an der Donau entlang.\nEin Besuch der Ruine Hin-\nterhaus macht die Wande-\nrung für Kinder zum Aben-\nteuer,\n\nWer die Biütenpracht\nnicht verpassen will, sollte\nrechtzeitig starten: Franz\nReisinger, Obmann des\nVereins Wachauer Marille,\nerwartet die Vollblüte für\ndie kommende Woche.\nEine genaue Beschreibung\nder verschiedenen Wander-\nrouten findet man unter\nweinbergwandern.at','\n',char(10)),'at_freizeit_waldviertel_01/image.webp','at_freizeit_waldviertel_01/thumb.jpg',93.4000000000000056,0,'manual','2026-03-09 11:39:34','2026-03-21 10:10:10','["Wachau", "Rossatz-Arnsdorf", "Krems-Angern", "Stift Göttweig", "Spitz"]','["weinbergwandern.at"]',NULL,NULL,NULL);
INSERT INTO articles VALUES(3,'at_freizeit_wolfgangsee_01.tif','2026-03-09','Kurier Freizeit',NULL,NULL,'Austria’s Next Top Reporter 02','Roswitha Klein, eine Top-Reporterin für Mondial, verbringt entspannende Tage im Salzkammergut. Sie genießt die Schönheit der Berge, Seen und Kultur des Salzkammerguts. Die Region bietet viele Möglichkeiten für Sport, Natur und Kultur.','Reise','["Salzkammergut", "Wanderung", "Kultur", "Sport", "Natur", "Wolfgangsee"]',replace('«s/HIMSL\n\nAustria’s Next Top Reporter 02\nin Oberösterreich\n\nVorgeschmack auf einen Urlaub an einem der schönsten Plätze der Welt: Roswitha Klein verbringt als Top\nReporterin für den Österreich-Spezialisten Mondial entspannende Tage im Salzkammergut.\n\nD: Orte: $t. Gilgen, Strobl und St. Wolt-\ngang. Vier Tage im „Weissen Rössl”, wo\ndas Glück nicht nur laut Operette, sondern\n\ntatsächlich vor der Tür steht. Unendlich die’\n\nMöglichkeiten des Zeitvertreibs. Drei Gipfel\nsind zu erklimmen. Zwölferhorn, Postalm und\n\n. der Schafberg, den man mit der Schafberg-\n\nbahn auch mühelos „bewandern” kann. Es\nlohnt sich, erwartet doch den Wanderer im\nSchutzhaus „Himmelpforte” der mit Abstand\n\nweltbeste Zwetschkenkuchen. Schwimmen,\n\nTauchen, Golfen, Segeln oder E-Biken, die\nneue Art den Wolfgangsee zu erkunden.\nRechtzeitig wurde im Vorjahr der Radweg\n\nAUS DER REGION\n\nDie Urlaubsentscheidung steht an. Wohin soll es\ngehen? In die Berge oder ans Wasser? Wir wollen\nviel erleben und uns gleichzeitig erholen. Berge und\nSeen würden uns gut zu Gesicht stehen, aber wos ist\nmit Natur und Kultur? Geht das alles wirklich unter\neinen Hut? Das Salzkammergut ist eine gute Wohl.\nWandern ist eine der lohnendsten Sportarten im\nSalzkammergut. Rerggipfel und Klettersteige wollen\nerobert werden. Für gemütlichere Touren locken\nPanoramawege und Almen mit urigen Hütten für die\nwohlverdiente Rost. Das Besondere am Salz-\nkammergut sind seine Glücksplötze. Das sind\nenergiereiche Natur- und Kroftplätze. Orte von\naußergewöhnlicher Schönheit, die eine geradezu\nmagische Kraft ausstrahlen.\n\nDer Drohtesel ist viel eher das Sportgeröt der Wahl?\nMehr ols tausend Kilometer erschlossene Mountain-\nbike-Wege und abwechslungsreiche Rodstrecken\nerwarten Profis wie Genussradler. Unbedingt\n\nWolfgangsee fertig, so dass man ungestört\nvom Verkehr den See entlang fahren kann.\n\nWELLENGANG. Die Wolfgangseeschiffe fah-\nren die Ausgangspunkte der Wanderungen\nan. Ein Tipp: aussteigen in Fürberg, und Rein-\nanke oder Saibling im Gasthof Fürberg genie-\nßen. Im Anschluss ein kleiner Spaziergang an\nder romantischen Uferpromenade nach St.\nGilgen. Von dort mit dem Schiff weiter, vorbei\nan Ochsenkreuzinsel und der imposanten Fal-\nkensteinwand, wo im Sommer immer wieder\nKletterer zu sehen sind. Kunst und Kultur ge-\nhören ebenso zum Salzkammergut. Eine inter-\n\nessante Galerie gibt es am Weg von St. Wolf-\ngang nach Strobl. Der Südtiroler Künstler Max\nLeonhard hat hier sein Atelier errichtet, in dem\ner bemerkenswerte, wind- und wetterfeste Sili-\nkon Außenbilder malt. Einzigartig: die Trach-\ntentreuve der „Salzkammergutler“. Wunderbar\nzu beobachten mit weich Freude und Stolz die\nBevölkerung die Tracht ausführt. Ja, es hat\nschon was, die strammen Wodln in gehäkel-\nten Stutzen zur bestickten Hirschledernen, da-\nzu ein zünftiger Hut mit Gamsbart. Das Salz-\nkammergut, wie es leibt und lebt ...\n\nFinden Sie den ganzen Bericht unter\nwww.mondiol-reisen.com/topreporter\n\nhier wird T, di ;\nnoch virklich gebt.\n\nausprobieren sollten Sie die neuen E-Bikes, die es\nvielerorts zum Verleih gibt. Und wer sich danach so\nrichtig verwöhnen lassen möchte, der ist in den\nThermen und Wellness-Hotels gut oufgehoben.\n\nDie Seen des Salzkammergutes mit dem klaren\n\nWasser höchster Güte laden zum Baden ein. Auch\nandere Wassersportarten werden im Salzkammergut\ngroßgeschrieben: Segeln, Surfen, Rudern, Tauchen\nund Trendsportorten wie Kitesurfen oder Parosailing\nversprechen sportlichen Spaß im kühlen Nass.','\n',char(10)),'at_freizeit_wolfgangsee_01/image.webp','at_freizeit_wolfgangsee_01/thumb.jpg',91.7999999999999971,0,'manual','2026-03-09 11:40:19','2026-03-21 10:11:23','["Salzkammergut", "Wolfgangsee", "St. Gilgen", "Strobl", "St. Wolfgang"]','["www.mondial-reisen.com/topreporter"]',NULL,NULL,NULL);
INSERT INTO articles VALUES(6,'it_gardasee_01.tif','2026-03-09','Kurier Immo','2026-03-07','5','HERBSTZAUBER AM GARDASEE','Das Quellenhof Luxury Resort Lazise in Italien bietet eine luxuriöse Umgebung mit Spa, Skypool, Naturbadesee und Aktivitäten wie Rad- und E-Bike-Touren, Tennis und Padel. Die Herbstliche Atmosphäre mit Blätterwechsel und ruhiger Seeatmosphäre macht jeden Moment unvergesslich.','Reise','["Luxury Resort", "Gardasee", "Herbst", "Aktivitäten", "Natur"]',replace(':0213, OF: 7\n\ngl\n\nHERBSTZAUBER AM GARDASEE\nQUELLENHOF LUXURY RESORT LAZISE\n\nGARDASEE, ITALIEN\n\nwww.quellenhof-lazise.it\n\nWenn der Herbst Lazise in goldene Farben taucht, offenbart das\nQuellenhof Luxury Resort Lazise seine besondere Magie. Umgeben von\nOliven- und Pinienhainen, oberhalb des malerischen Städtchens, ge-\nnießt man atemberaubende Ausblicke auf das Süd-Ostufer des Garda-\nsees. Die moderne Architektur und das außergewöhnliche Design\nschaffen ein stilvolles Ambiente für Genuss und Erholung. Im 2.000 m?\ngroßen Spa verfliegt jeder Stress, während der Skypool im Adults-Only-\nBereich und der Naturbadesee zum Verweilen einladen. Aktivurlauber\nschätzen Rad- und E-Bike-Touren, Tennis, Padel oder das abwechslungs-\nreiche „Feel Moved“-Programm. Feinschmecker erleben kulinarische\nHöhepunkte, Golfer finden nahe Golfplätze, und die luxuriösen Suiten\nund Penthouse-Poolvitllen bieten Rückzugsorte voller Eleganz. Herbst-\nliche Spaziergänge durch die Gärten, das sanfte Rascheln der Blätter\nund die ruhige Seeatmosphäre machen jeden Moment unvergesslich.\n\nKlausen\nBarbian\nFeldthurns\nViltanders\n\nSANFTER WINTER IN KLAUSEN\nWO DIE ZEIT LEISE WIRD\n\nEISACKTAL, SÜDTIROL\n\nwww.klausen.it\n\nDer Winter in Klausen erzählt von Stille, die knirscht, wenn Schritte\nSpuren in den Schnee zeichnen. Von Luft, so klar, dass jeder Atem-\nzug wie ein kleines Geschenk wirkt. Von Wegen, die hinausführen\nauf die Villanderer Alm, wo die Sonne über weiße Weiten streicht,\ndas Glitzern der Schneekristalle den Blick fesselt und ein 360-Grad-\nPanoramablick auf die Dolomiten begeistert. Winterwandern, Schnee-\nschuhe anschnalten, Rodeln oder auf Langlaufskiern durch die Land-\nschaft gleiten - hier wird Bewegung zum sanften Spiel mit der Natur.\nUnd wenn in den Hütten das Holz im Ofen knackt, der Duft von Suppe\nsteigt und ein Glas Wein die Seele wärmt, dann verlangsamt sich die\nZeit fast von selbst. Ein Lächeln im Gesicht, rote Wangen von der Kälte\nund das Gefühl tiefer Ruhe - so zeigt sich der Winter in Klausen. Er ist\nkein Programm, sondern ein Gefühl: leicht, klar, wohltuend - wie ein\ntiefer Atemzug, der lange nachklingt.','\n',char(10)),'it_gardasee_01/image.webp','it_gardasee_01/thumb.jpg',93.2000000000000028,0,'manual','2026-03-09 11:43:02','2026-03-09 16:25:15','["Gardasee", "Lazise"]','["www.quellenhof-lazise.it", "www.klausen.it"]',NULL,NULL,NULL);
INSERT INTO articles VALUES(7,'at_kurier_ooe_00.tif','2026-03-15','KURIER','2024-12-05','41','Michael Schottenberg entdeckt Oberösterreich','Der Wiener Michael Schottenberg hat nach vier Bundesländern sein viertes Bundesland, Oberösterreich, entdeckt. Er beschreibt seine Reise als eine Erforschung der Vielfalt der Regionen, die aus vier Vierteln besteht. Er betont die harmonische Verbindung von majestätischen Bergen und sanften Hügeln, von endlosen Ebenen bis hin zu ruhigen Gewässern.','Reise','["Michael Schottenberg", "Oberösterreich", "Reise", "Vielfalt", "Regionen"]',replace('3\n\nFi\n\nicht nur in der Fremde\nN: ich mich überra-\n\nschen. Auch in der Hei-\nmat. Von einem Land, das ich\nzu kennen glaube, auf Schritt\nund Tritt aber mit neuen, fan-\ntastischen Geschichten kon-\nfrontiert werde. Vieles gites zu\nentdecken. Was prägt die Ge-\n\ni ft einer Region, wo\nverbergen sich Tradition und\nvergessenes Handwerk, wo In-\nnovation und Kreativität? Die\nAuswahl der Gesprächspartner\nist mindestens so entscheidend\nwie die Neugier des Reisenden.\nSchritt für Schritt eroberte ich\nmir das Land oberhalb und\nunterhalb der Enns, fuhr kreuz\nund quer, hügelauf, hügelab,\nentdeckte, staunte, und machte\nvor allem eines nicht: einen\nPlan. Neuland lässtsich am bes-\nten unvorbereitet erfahren.\n\nDer Blick auf Unbekanntes\nerscheint mir als eine der\nHeu zu osdnen, um mich vor\nWie oft habe.ich fremde Län-\nder bereist? Für diesmaf habe\nich mir vorgenommen, inner-\nhalb der Grenzen zu bleiben.\nErschien mir das Vertraute bis-\nlang nicht interessant genug?\nDie Neugier beginnt vor der\neigenen Haustüre. Nicht die\nGeografie entscheidet, die\nSeelen der Menschen bestim-\n\nMichael ''\nDer Wiener (geb. 1952) ist seit\n1975 Fixgröße auf Bühne, in TV\nund Kino, auch als Regisseur. Ab\n2005 leitete er zehn Jahre das\nVolkstheater, seit 2015 ist er\nReiseautor. 2019 wurde er bei\n„Dancing Stars“ Zweiter\n„v\n& KURIER verlost drei signierte\n\nWERTEN\n\nNN\n\nAII/REIDE\n\nReisen | 41\n\nMN LET\n\nDas Herzklopfen\n\nReise-Promi. Schauspieler Michael Schottenberg entdeckte nun nach\nder Welt sein viertes Bundesland, Oberösterreich - wie gewohnt per\nVespa. Für den KURIER schrieb er ein Persönliches Resümee\n\nmen Fremde. Oder Nähe.\nOberösterreich! Beinahe\nein ganzes Jahr lang war ich\nunterwegs. Was für eine Lust,\neine Welt zu erkunden, die aus\nvier Vierteln besteht, dachte\nich. Ich sollte recht behalten.\nHausruck-, Inn-, Traun- und\nMühlviertel gleichen in ihrer\nVielfalt. einem Kaleidoskop,\ndas Funkeln für denjenigen\nbereithäk, der zu erkennen\nvermag, Vom Ufer des mächti-\ngen Inn bis zum Böhmerwald,\nvom Sengsengebirge bis ins\nergut, von den Ge-\nstaden des Traunsees bis zum\n\n. Schlinge - auf mieiner roten\n\nRegionen. Ich kam: ans dem\nStaunen nicht heraus. Die\nSchönheit der Landschaft er-\ngibt sich aus der harmoni-\nschen Verbindung von majes-\ntätischen pfeln und\nsanften Hügeln, von endlosen\nEbenen bis hin zu ruhigen Ge-\nwässern - die Vielfalt der Na-\ntur und die Einzigartigkeit\n\nEn\n\nFAN;\n\na\n\nMiteinander’;\n\Imen und We\n\nGespräch über das Scheitern\n‚a stillen Ort/Schiffismuseum\n\nder Topografie formen eine\nKulisse, die Staunen nacht\nWie viel Neuland durfte\nich betreten, und wie oft verlor\nich mich in Lebensentwürfen?\nHerzenswärme und Humor\nzeichneten meine Begegnun-\ngen ''aus. Mal ware es\n\nVielfalt der Regionen, hier die\nSchlögener (Donau-)Schlinge\n\nZufälligkeiten, die das Leben\nmeiner Gesprächspartner be-\neinflussten, mal das bewusste\nErkennen des Augenblicks.\nWie Prismen unterschiedli-\ncher Farben und Formen füg-\nten sich meine Polaroidauf-\nnahmen zu einem Ganzen und\n\nv\nBegegnung\nvon Mutter“\n\nkühen und\nHunden ver\nmeiden!\n\nergaben das Identitäts-\ndiagramm eines Landes. Ich\nbefüllte einen Zettelkasten\nder besonderen Art - mit Un-\nbekanntem, Überraschen-\ndem, Verborgenem.\n\nDie Welt rund um mich\nbetrachtete ich wie ein Ge-\nmälde, achtete auf die Schat-\ntierungen der Gedanken, und\nwarf einen Blick hinter den\nHorizont von Geschichten.\nWie ein Schmetterlingsjäger\nsammelte ich Beiläufigkeiten,\nWorte, Gesten. Aus all dem\nergaben sich Bilder, die sich\nzu einer Welt neuen Seins zu-\nsammensetzten. Aus der Viel-\nfalt der Unterschiedlichkeiten\nerschloss sich mir die Seele\neines Landes: Die des Tierprä-\nparators Höller, in dessen\nDachboden Thomas Bernhard\nseinen Roman „Korrektur“\nschrieb, die der kapriziösen\nHolzkünstlerin Annerose R,\ndie mit der Kettensäge Puppen\nschnitzt, die des Bäckermeis-\nters, der eine Wunderkammer\nvoll mit Brotkunstwerken be-\n\nDen bier\narbeitenden\nMenschen, der Natur\nund den Tieren\nmit Respekt\nbegegnen! 6\n\nEN kurzer Leine !\n\nsitzt, die des Riesen, der so\ngroß war, dass er die Welt zu\nseinen Füßen nicht mehr sah,\ndie der Frau, die auf ihrer Toi.\nlette ein Schiffsmuseum be-\ntreibt und über den Sinn des\nScheiterns nachdenkt, die des\nLehrers, dessen Name zur\nVokabel wurde und der latei-\nnische Verse in Mundart über-\ntrug, und die des Linzer Dom-\nEremiten, der sich zu meiner\ngroßen Verwunderung als der\nAutor selbst, also ich, ent-\nPuppte.\n\n„Alter ist ein Geschenk,\nwenn man nicht vergessen\nhat, was Anfangen heißt“, .\n‚sagt der Philosoph Martin\nBuber. Wie immer am £\neiner Reise war ich aufgeregt\nund fühlte mich jung. Oberös-\nterreich zu bereisen, heißt,\nseine Bewohner verstehen\nund lieben zu lernen. Wahr-\nscheinlich ist es das, das mich\nantreibt und wonach ich mich\nsehne: das Herzklopfen. Ich\nwollte ein Buch über ein Land -\nschreiben. Ich schrieb eines\nüber Menschen. : Fr,\n\nKURIER Talk . !\n\n'' Oberösterreich; Reiseauto,\n\nNichael Schottenberg über\n\nMenschen, Begegnungen,\nGeschichten und Abenteuer\n19. 5. um 19.00 Uhr auf\nKURIER TV, KURIER.at\n\nHunde ar\nuhren\n\nH durer\nIst ein Angrif dure\n\nein Weidetie'' abzu-\nsehen: Soto:t\nableinen!','\n',char(10)),'at_kurier_ooe_00/image.webp','at_kurier_ooe_00/thumb.jpg',89.5999999999999943,0,'manual','2026-03-15 16:50:50','2026-03-15 16:53:45','["Oberösterreich"]','[]',NULL,NULL,NULL);
INSERT INTO articles VALUES(8,'sternlicht_oase_p01.tif','2026-03-16','Kurier Freizeit','2026-01-31','12','Nachterlebnis draußen in der Natur ist groß','Die Nachfrage nach Nachterlebnissen in der Natur ist groß, aber nur in wenigen ''Sternlicht-Oasen'' kann man noch den klaren Blick haben. 2001 begannen der Verein Kuffner-Sternwarte und die Universität Wien das Thema Lichtverschmutzung zu behandeln. Das Lichtverschmutzung führt zu einer starken Veränderung der Sterne, die nur noch 90 Prozent der Sterne mit freiem Auge wahrnehmbar sind. Ziel ist es, den Lichtzustand zu erhöhen, um belastbare Indikatoren zu erhalten, auf denen Maßnahmen zum Schutz der Nacht entwickelt werden können.','Wissenschaft','["Lichtverschmutzung", "Sternwarte", "Astrophysik", "Nachterlebnis", "Natur"]',replace('GRÜNE WELT end\n\n\Wo es immer noch\nrichlig Nacht wird\n\nDie Nachfrage nach dem Nachterlebnis draußen in der\nNatur ist groß. Doch nur in wenigen\n“Sternlicht-Oasen“ hat man noch den klaren Blick.\n\nm Jahr 2001 begannen der\nVerein Kuffner-Sternwarte\nund die Universität Wien\ndas Thema Lichtverschmur-\nzung unterdie Leute zubrin-\ngen. „Wie viele Sterne sehen\nwir noch?“ fragten sie im Rahmen\neiner Kampagne, der sie die Beobach-\ntung des „Kleinen Wagens" zugrun-\nde legten. Das Idealbild, im Foto,\nwurde der Wirklichkeit gegenüber\ngestellt. Das Echo war groß, 2.500\nMeldungen gingen ein, mit dem er-\nnüchternden Ergebnis, dassdasStern-\nbild kaum noch irgendwo komplett\nzu sehen war.\n„Der,KleineWagen’ hat ein Rad ver-\nloren“, kommentiert das der Astro-\nnom und Leiter der Kuffner-Stern-\nwarte, Günther Wuchterl, heute. Er\ngehört zu den Pionieren und Archi-\ntekten einer immer lautstärker wer-\ndenden Bewegung zur Bewahrung\nder Nacht.\nImmer schon war die Dunkelheit ein\nTeil des Lebens. Jetzt hat das Schwarz\nder Nachtaberkaum mehreineChan-\nce.Sobald.dieSonneuntergeht, gehen\ndieLichteran. Zuviele. DieKinderder\n24-Stunden-Gesellschaft kennen kei-\nne Milchstraße mehr. Die orangefar-\nbenen Lichtglocken über den Städten\nfluten weit hinaus ins Umland und\nauch in der Landschaft hat beispiels-\nweise die Beleuchtung von Bergsta-\n\ntionen die Nacht vertrieben. „Licht-\nverschmutzung“ nennen Experten\ndieses Phänomen, das den Sternen-\nhimmel für den Betrachter verblassen\nlässt. AufSatellitenbildern der NASA\nerkennt man die Lichtkonzentration\nin den Industrieländern und den\nMegastädten. Shanghai, Tokio und\nDubai sind unrühmliche Spitze. Die\ngrößte Lichtkonzentration hat Euro-\npa aufzuweisen und das nicht nur in\nden Städten. Ein Quadratkilometer\nholländischer Tomatengewächshäu-\nser soll nachts über vierzig Mal heller\nstrahlen als eine vergleichbare Fläche\nin Manhattan.\n\nDas Lichtfeuerwerk bewirkt, dass\n90 Prozent derfrühermitfreiem Auge\nwahrnehmbaren Sterne „verschwin-\nden“. Es können auch astronomische\nPhänomene wie Sternschnuppen und\nleuchtende Kometen nur noch fernab\nder Lichtglocken um die Städte beob-\nachtet werden.\n\nPunktuell gibtessieabernoch, die un-\nberührten Nachtlandschaften. Bei-\nspielsweise im „Wildnisgebiet Dür-\nrenstein-Lassnigtal“ in Niederöster-\nreich, wosichauchdergrößteUrwald-\nrest des Alpenbogens erhalten hat.\nDort, aufder Legsteinalm betreut As-\ntronom Wuchterl schon seit 2010\neine Messstation auf dem Dach einer\nalten Jagdhütte.\n\nZiel ist es, den Lichtzustand zu erhe-\n\nben, um belastbare Indikatoren zu er-\nhalten, auf denen Maßnahmen zum\nSchutz der Nacht entwickelt werden\nkönnen, darunter die Anerkennung\nder letzten „Sternlicht-Oasen“ als\nUNESCO- Weltnaturerbe.\n\nZu den rar gewordenen Plätzen, an\ndenen noch die vielen Milliarden Ster-\nne des Milchstraßenbandes in einer\nHelligkeit erscheinen, wie sie sonst\nnur in Wüstengegenden oder den\nBergen Chiles zu finden sind, zählt\nüberraschenderweise auch der 1.900\nSeelenort Großmugl, nur 33 Luftkilo-\nmetervon Wienentfernt. Dasliegtan\nder besonderen topografischen Gege-\nbenheit, dasseineumgebende Hügel-\nkette die Lichtsmog-Glocke abhält.\n\nDie Milch-\nstraße über\ndem Wild-\n\nnisgebiet\n\nLassnitztal\nin den Ybbs-\n\ntaler Alpen','\n',char(10)),'sternlicht_oase_p01/image.webp','sternlicht_oase_p01/thumb.jpg',91.7000000000000028,0,'manual','2026-03-16 09:28:50','2026-03-16 09:47:20','["Wildnis Dürrenstein-Lassingtal"]','["https://www.wildnisgebiet.at/"]','sternlicht_oase',1,NULL);
INSERT INTO articles VALUES(9,'sternlicht_oase_p02.tif','2026-03-16','Kurier Freizeit','2026-01-31','13','Sternentourismus: Nachthimmelwandern','Der Sternentourismus, eine neue Form der Naturbegegnung, bietet sich an, insbesondere in wenigen Sternlicht-Oasen mit klarem Blick in den Sternenhimmel.','Wissenschaft','["Sternentourismus", "Nachthimmelwandern", "Sternlicht-Oase"]',replace('„Man spürt die Unendlichkeit, man\nertrinkt in lauter Sternen,“ schwärmt\nWuchterl von dem Nachterlebnis,\ndas sich oben auf der Leebergwiese —\nbeieinem der schönsten Hügelgräber\nder Hallstattkultur — den Hobbyas-\ntronomen und Astrofotografen\nbietet.\n\nNoch ist er fast ein Geheimtipp: der\nSternentourismus. Während sich\nGletscher, klimabedingt der sportli-\nchen Nutzung entziehen, Skilifte\nsperren, weil ihr Betrieb den Gemein-\nden und ihre Nutzung den Skifahre-\nrinnen und Skifahrer zu teuer werden,\nsteigt das Interesse an einer neuen,\nsehr stillen Form der Naturbegeg-\nnung: „Nachthimmelwandern" —\n\nDie Nachfrage nach dem Nachterlebnis in der Natur ist groß. Doch nur in wenigen „Stern-\nlicht-Oasen“ hat man noch den klaren Blick in den unendlichen Sternenhimmel','\n',char(10)),'sternlicht_oase_p02/image.webp','sternlicht_oase_p02/thumb.jpg',91.7999999999999971,0,'manual','2026-03-16 09:29:33','2026-03-16 09:47:56','["Wildnis Dürrenstein-Lassingtal"]','["https://www.wildnisgebiet.at/"]','sternlicht_oase',2,NULL);
INSERT INTO articles VALUES(10,'sternlicht_oase_p03.tif','2026-03-16','Kurier','2025-12-13','14','Winterangebote für Sternwartenbesucher','Der Astronom Günther Wuchterl führt am 13. Dezember eine Sternschnuppenfahrt durch. Die Geminiden sind ein starker Sternschnuppenstrom, der nach dem Sternbild Zwillinge benannt ist. Die Fahrt findet in der Kuffner-Sternwarte in Wien statt.','Wissenschaft','["Sternschnuppen", "Sternwarte", "Wissenschaft", "Wien", "Geminiden"]',replace('GRÜNE WELT; vol\n\nöffnet im Sommer und im Winter den Blick in\ndie Weiten des Universums.\n\n„Mitte Dezember“, sagt der Astronom\nGünther Wuchterl, „beeindruckt jedes Jahr\nder Schnuppenstrom der Geminiden“. Be-\nnannt ist ernach dem Sternbild der Zwillin-\nge, lateinisch Gemini, und ist bekannt für\nseine hohe Rate an Sternschnuppen pro\nStunde. Am 13. Dezember wird Wuchterl\nInteressierte auf den Weg zu den Sternen\nbegleiten (siehe Kasten).\n\nWinterangebote gibt es vom Tiroler Kauner-\ntalüberden Naturpark Attersee-Traunsee bis\nnach Großmugl. Die Astrotourismus-Vorzei-\ngegemeinde will jetzt auch wieder die büro-\nkratische Arbeit aufnehmen, die es benötigt,\nUNESCO-Schutzstatus zu erwerben. Ein\nerster Versuch 2017 war fehlgeschlagen.\n\nIm neuen Anlauf will man jetzt gleich im\nStück, als erste Gemeinde weltweit, Weltkul-\ntur- und nicht „nur“ Weltnaturerbe werden.\nIndem man das Anliegen in einen umfassen-\nderen Zusammenhang stellt, nämlich in den\nmit der Hallstatt-Kultur.\n\nLängst geht es um mehr als um ein beschauli-\nches „Sternderlschauen“, nämlich um die\nRettung der Nacht.\n\nINGRID GREISENEGGER\n\nTeleskop in der\nKuffner-Stem-\nwarte. Satum,\nJupiter oder die\nPlejaden rücken\ndort näher\n\nSTERNFAHRT ZU DEN\nGEMINIDENSCHNUPPEN\n\nSamstag 13. Dezember 2025\nTreffpunkt: Kuffner-Sternwarte,\nJohann Staud-Straße 10, 1160 Wien\num 17 Uhr\n\nLeitung: Prof. Dr. Günther Wuchterl\nDie Geminiden sind ein starker Stern-\nschnuppenstrom, der nach dem Stern-\nbild Zwillinge benannt ist. Wenn die\nErde im Dezember diese Staubwolke\nauf ihrer Bahn kreuzt, dringen die Teil-\nchen in die Atmosphäre ein und erzeu-\ngen als Sternschnuppen sichtbare\nLeuchtspuren am Himmel. Der Höhe-\npunkt liegt in der Nacht vom 14. auf\nden 15.Dezember. Abhängig vom Wet-\nter am 13. Dezember wird entschie-\nden, wann und zu welchem Ort man\ngemeinsam (in Fahrgemeinschaften)\naufbricht, beispielsweise zur Aflenzer\nBürgeralm oder ins Wildnisgebiet am\nDürrenstein.\n\nAnmeldung und Information:\ngeminiden@kuffner-sternwarte.at','\n',char(10)),'sternlicht_oase_p03/image.webp','sternlicht_oase_p03/thumb.jpg',92.9000000000000056,0,'manual','2026-03-16 09:30:35','2026-03-21 10:13:27','["Wien", "Kuffner Sternwarte"]','["https://kuffner-sternwarte.at/index.php", "geminiden@kuffner-sternwarte.at"]','sternlicht_oase',3,NULL);
INSERT INTO articles VALUES(12,'brot_2026-03-20_00.tif','2026-03-20','Kurier','2025-10-20','25','Brot ist nicht gleich Brot','Die Ernährungsmedizinerin Michaela Axt-Gadermann und Brotsommelier Johannes Dackweiler erklären in ihrem Buch "Fit & schlank mit Brot", warum viele Brotsorten gesund sind und beim Abnehmen helfen können. Eine Studie belegt, dass ballaststoff- und proteinreiches Brot in drei Monaten zu über 1,8 kg Gewichtsverlust führen kann. Das Buch enthält zudem Rezepte für verschiedene Bedürfnisse sowie eine Entwarnung zum Thema Gluten.','Ernährung','["Brot", "Gesundheit", "Ernährungsexpertin", "Bio-Bäcker", "Gluten"]',replace('HANS GLADER / NATURSCHUTZBUND\n\nBrot ist\nnicht gleich\nBrot\n\nA\nu\n\nGenuss. Eine Ernährungsexpertin und\n\nein Bäcker erklären in ihrem neuen\nBuch, worauf es beim Brot ankommt -\nund liefern passende Rezepte.\n\nVon Lilsa Mikkola\nBrot gilt als Dickmacher - zu\nviele Kohlenhydrate, zu viele\n\nBuch „Pit &s mit Brot“,\n\ndas sie mit dem Bio-Bäcker -\n\nJohannes Dackweiler ge-\nschrieben hat.\n\nDarin wird erklärt, wa-\nrum viele Brotsorten sehr ge-\nsund «sind und welche ge-\n\n“sundheitsförderlichen Wir-\n\nkungen Getreide und seine\nBestandteile auf Herzgesund-\nheit, arınflora,\nVerdai -Kreißlauf-\n\nit haben. Es wer-\n\nden Backwaren und Rezepte\nfür unterschiedliche Bedürf-\nnisse. vorgestellt: mit vielen\nBallaststoffen, mit hohem\nProteingehalt, für einen ge-\nsunden Darm, glutenfreie\noder histaminarme Brote.\n\nToast ys. Vollkornbrot\nDass Brot per se von vielen In-\nfluencexb:;noch immer als\n\neinen Kamm scheren. Wir\nkönnen ein helles Toastbrot\nmit Schokoaufstrich nicht\nvergleichen mit einem Voll-\nkornbrot, das mit einem Ge-\nmüseaufstrich oder einem\nmageren Käse oder einer\nScheibe Lachs belegt ist. Brot\nist nicht gleich Brot und na-\ntürlich spielt auch der Belag\neine wichtige Rolle.“\n\nBrot kann, je nach Zusam-\nmensetzung, sehr gesund\nsein und entzündungshem-\n\n- mende Ballaststoffe liefern,\nschützende Antioxidantien,\nVitamine, Spurenelemente\nund gesunde Fette.\n\nGewichtsverlust mit Brot\n\n* Mit mandiien Sorten lässt sich\nsogar abnehmen. Das hat eine\nStudie des Westdeutschen\n\nDiabetes- und Gesundheits- .\n\nzentrums in Düsseldorf ge-\nzeigt: Verglichen wurden ein\nklassisches Roggenbrot mit\neinem eiweiß- und ballast-\nstoffreichen Brot.\n\nDie Gruppe mit dem bal-\nlaststoff- und proteinreichen\nBrot verlor in drei Monaten\nüber 1,8 Kilos. Und das, ob-\nwohl beide Brote fast die glei-\nche Kalorienmenge pro 100\nGramm lieferten und keine\nanderen Ernährungsempfeh-\nlungen gegeben wurden. „Na-\n\n$ 509 nenschrot\nSa; 9 Flohsamenschalen\n«1 Päckchen Weinsteinback-\npulver oder normales\n.250g Magertopfen\n\n+3 Eier\n\n« 10. mi Otivenöl\n\n« 10 9 Balsamicoessig oder\n\nig :\n+ 400 mi Wasser\n.15 95a\n+ Fett für Backform, Saaten\nZubereitung:\n1. Kerne, Kleie, Süßlupinen-\nmehl, Leinsamenschrot\nund Flohsamenschalen mit\ndem Weinsteinbackpulver\nPa In einer\n\nern, 9. Essig, Wasser\nund Salz verrühren.\n\n«\nww\n‘19\n=\nz\n\n2. Die Masse mit Mehlge-\nmisch gut vermengen und\nkräftig durchkneten. Einen\nLaib formen, der in einer\nkleinen Kastenform oder auf\neinem Backblech gebacken\nwird. Oberfläche anfeuchten\n\n"und mit Saaten bestreuen.\n\n3. Das Brot 45-55 Minuten\n\n. bei 180 °C (Umluft) backen.\n\nTipp: Dazu passt ein cremiger,\nmild gesäuerter Topfen, ange-\n4. rührt mit Gartenkräudern wie\n\n* Schnittlauch, Dille sowie\n\neinem Schuss Zi Zi tronensaft.\n\nTICTIZCA.\n\nBEATSS/ISTOCKPHOTO COM\n\ntürlich kommt es auch darauf\nan, wie viel Brot-Kalorien ich\n\n"täglich zu mir nehme und was\n\nich sonst noch esse“, ergänzt\nAxt-Gadermann.\n\nAuch das Thema Gluten\nspielt in dem Buch eine Rolle.\nDie Ernährungsmedizinerin\nhat dazu eine klare Meinung:\n„Die Angst vor Gluten ist un-\n\nFlugverkehr. Während es heimische Vögel jetzt in den\nSüden ziehen, empfängt Österreich Wintergäste aus dem Norden. Seite 26\n\nbegründet, wenn man nicht\nunter bestimmten Erkrankun-\ngen leidet wie Zöliakie oder\nWeizenallergie. Studign wie-\n\nsen nach, dass Personen, die .\n\nauf Gluten verzichten, oft\neine höhere Schwermetallbe-\nlastung und eine schlechtere\nVersorgung mit Nährstoffen\naufweisen.“\n\nLeinsaat-Nuss-Brot\n\n« 80 9 Walnusskernre\n\n« 140 g Sonnenbtuimenkerne\n+ 100 g Leinsamen\n\n« 40 9 Flohsamenschalen\n« 150 g Leinsamenmehl\n« 1% TL feines Meersalz\ne 4EL Walnussöl:\n\n« 1TL Rohrohrzucker\n\n« 450 ml Wasser\n\n« etwas Leinsamen zum\nBestreuen\n\nZubereitung:\n\n1. Kastenform mit Back-\npapier auslegen. Die\nWalnüsse hacken. Mit den\nSonnenblumenkernen, Lein-\nsamen, Flohsamenschalen,\nLeinsamenmehl und Meer- °\nsalz in einer Rührschüssel\nmit einem Schneebesen\nvermischen.\n\n2. ÖL Zucker und 350 ml\nWasser in mehreren\nPortionen mit den Quirlen\neines Handrührgeräts‘\nunterrühren. Den Teig in\nKastenform füllen, glatt\n\nx\nw\no\nFi\nz\n©\n2\nz\n\nstreichen und zugedeckt\n3 Stunden quellen lassen.\n3. Den Backofen auf 180 °C\n\n. (Ober-/Unterhitze) vorheizen.\n\nDas Brot mit Leinsamen\nbestreuen und im Ofen auf\nmittlerer Schiene 60-70\nMinuten backen.\n\n4. Das Brot aus dem Ofen\n\nnehmen und auf Kuchen-\n\ngitter 10 Minuten abkühlen\nlassen. Dann aus der Form\nlösen und vollständig\n\n‚auskühlen lassen. Kühl und\n\ntrocken gelagert, bleibt es\nbis zu 1 Woche saftig.\n\nKultur\n\n“Medien &\n\nVolikornweckerl\n\nZutaten: -\n\n+ 250 ml kaltes Wasser\n\n+ 1 TL Kokosblütenzucker\n\n« 15 g frische Hefe\n\n+ 300 g Dinkelvollkornmehl\n« 100 g Haferflocken, fein\ngemahlen\n\n+ 50 g Leinsamen, geschrotet\n-1TLSalz\n\n« 2EL Olivenöl\n\n« Sonnenblumenkerne,\nKürbiskerne oder Sesam\n\n1. Am Vorgbend das kalte\nWasser mit Kokosblütenzu-\ncker mischen und die Hefe\ndarin auflösen. Hier muss\nkeine Wartezgit eingeplant\nwerdei?da der Teig langsam\nim Kühlschrank reift.\n\nve\n\n2. In elffpr.gfaßen Schüssel\ndas hl, die\ngemaltilenen Haferflocken,\n\nLeinsamen und Salz\nvermischen. Das Hefe-\nWasser und das Olivenöl\nhinzugeben und alles zu\neinem geschmeidigen,\nleicht klebrigen Teig kneten.\nFalls der Teig zu trocken ist,\nWasser hinzufügen.\n\n3. Den Teig in der Schüssel\nabdecken (mit Deckel oder\nFrischhaltefolie) und für\nmindestens 12 Stunden\n{über Nacht) im Kühlschrank\nruhen lassen,\n\n4. Am nächsten Morgen den\n\nTeig aus dem Kühlschrank\n\nMenschen\n\n25\n\n20. Oktober 2025\n\nFakten\n\nBrotkonsum\n\nMehr als jeder dritte\nÖsterreicher isst\n\ntäglich Brot und\nGebäck. Pro Jahr .\nwerden hierzulande\nrund 41,5 kg Brot pro\nKopf verzehrt. Das\nentspricht etwa 2-3 .\nScheiben Brot täglich.\n\nLagerung\n\nIdeal ist ein Römer-\ntopf aus Ton. Alter-\nnativ lagert man Brot\nim Kühlschrank. Von\neiner Brotdose aus\nMetall raten die\nExperten ab, da sie\nkeine Feuchtigkeit\nspeichert und regu-\nliert.\n\nBuchtipp\n\n„Fit & schlank mit\nBrot” von Ernährungs-\nmedizinerin Michaela\nAxt-Gadermann und\nBrotsommelier\nJohannes Dackweiler,\nerschienen im\nSüdwest Verlag.\n\n176 Seiten,\n\nca. 21 Euro.\n\nINGO HILGER\n\nnehmen und 10-15 Minuten\nbei Raumtemperatur ruhen\nlassen, damit er etwas\nweicher wird. Den Teig auf\neine leicht bemehlte Arbeits-\nfläche geben, in 8 gleich\ngroße Portionen teilen\n\nund zu Brötchen formen.\n\n5. Den Ofen auf 220 °C\n(Ober-/Unterhitze) vorheizen.\nDie Brötchen auf ein mit\n\n. Backpapier ausgelegtes\n\nBackblech legen und bei -\nZimmertemperatur noch\neinmal 20-30 Minuten\ngehen lassen, während der\n\n‘ Ofen vorheizt.\n6. Optional: Die Brötchen mit\netwas Wasser bestreichen\nund mit Sonnenblumen-\nkernen, Kürbiskernen\nund/oder Sesam bestreuen.\n7. Die Brötchen 20-25\nMinuten backen, bis sie gold-\nbraun und knusprig sind.\nNach dem Backen auf\neinem Gitter abkühlen\nlassen.','\n',char(10)),'brot_2026-03-20_00/image.webp','brot_2026-03-20_00/thumb.jpg',89.0,0,'auto','2026-03-20 17:15:15','2026-03-20 17:24:33','[]','[]',NULL,NULL,NULL);
INSERT INTO articles VALUES(13,'reise_nuernberg_2026-03-20_00.tif','2026-03-21','KURIER','2023-12-24',NULL,'Lebkuchen backen bei den Profis','Der mittelhochdeutsche Lebkuchen war ein Energieriegel, um die karge Winterzeit zu überstehen. Heute muss man sich nicht um zu wenig, eher um zu viel Hüftgold sorgen. Kochschule cookionista bietet in Nürnberg diverse Workshops an.','Reise','["Lebkuchen", "Kochschule", "Nürnberg", "Winterdorf"]',replace('. KURIER.AT/REISE\n\nNUN NN\n\nSonntag, 24. ‚ Dezember 2023\n\nNürnberg, Deutschland\nLebkuchen backen bei den Profis\n\nDer mittelhochdeutsche lebekuoche war ein\nEnergieriegel, um die karge Winterzeit zu\nüberstehen. Heute muss man sich nicht um zu\nwenig, eher um zu viel Hüftgold sorgen - dieser\nGedanke’kasrent, wenn man über den Nürnber-\nger Christkindlesmarkt schlendert. Ruhiger\ngeht es wenige Meter hinter dem Graben\n(nordwestliche Ecke) zu, der die Altstadt ein-\n.. grenzt. Die Kochschule cookionista bietet in\nu tebleachen-Workshöps\n„Die Deutschen haben den Lebkuchen\nnicht erfunden“, sagt Koch Harald Heiselbetz\n„während die Teilnehmerinnen und\nTeilnehmer ihre Schürzen umbinden; und\nwartet, bis er wieder die volle Aufmerksam-\nkeit hat: „Sie haben ihn nur perfektioniert.“\nDer schnörkellos eingerichtete Kubus mit\nGlasfassade ist in der Mittelalterstadt ein mo-\nderner Kontrapunkt. Neunzig Minuten dauert\nder Crashkurs, an diesem Tag nehmen auch\nAmerikaner, eine Inderin und ein Chinese teil.\nAlle finden es exciting, man lässt sich also als\nLebkuchen-erfahrener Österreicher vom ginger-\nbreadfever rührt und patzt und\nformt mit. Im Grunde brauche es hicht viel:\n„Kardamom, Nelken und Zimt sind eine gute\nBasis“, so Heiselbetz. Wichtig sei die Qualität\nund Frische der Gewürze. „Wenn die Gewürze\nnicht frisch sind, kannst du genauso gut mit\nStaub arbeiten.“ Einfache, aber gute Tipps:\nUm das beste Ergebnis zu erzielen, sollte der\nOfen vorgeheizt werden. Wer mehrere Bleche\nLebkuchen gleichzeitig backen möchte, sollte\nUmluft statt Ober-/Unterhitze einstellen.\n\nEine beliebte Sonderform sind „Elisen“.\nUm diese Bezeichnung tragen zu dürfen, muss\nein Lebkuchen mindestens fünfun\nProzent Edelkerne enthalten. In der Regel\n\n“ sind das Mandeln, aber auch Haselnüsse oder\n\nWalnüsse,. Ebenso darf der Mehlanteil (bezie-\nhungsweise Getreidemahlerzeugnisse) bei\nmaximal zehn Prozent li\n\negen.\nAm Ende holt Heiselbetz die Erzeugnisse\n\nso aus wie erwartet: unförmig. Die Inderin\nwirkt enttäuscht. Man wolle dann doch noch\nbei alteingesessenen Bäckereien einkaufeli.\nNur wo? „Eine der besten Lebküchnereien ist\ndie Gebr. Fraunholz Elisenlebküchnerei, dort\nwerden die Elisenlebkuchen traditionell ohne\nMehl gebacken.“ (fraunholz-lebkuchen.de)\nAuch nicht altbacken sind die Rezepte, die\ncookionista.com anbietet: „Winterliches Roast-\nbeef mit würziger Lebkuchen-Kräuterkruste“,\nzart im Ofen gegart. Oder als Dessert: Mango-\ncreme mit Lebkuchenchips. STEFAN HOFER\n\nTOP 3\n\nKochkurse Ob Thai-Food, Sushi, 1001 Nacht oder\nVeggie-Küche: Cookionista bietet in Nürnberg\ndiverse Workshops an: cookionista.com/events\nSävester Am Jakobsptatz hinter dem Weißen Turm\neröffnet am 24. Dezember erstmalig das Winterdorf\nmit Riesenrad (bis 7. Jänner 2024). nuernberg.de\nDeutsche Geschichte Von der Kaiserburg über das\nDürer-Haus bis zum Dokumentationszentrum\nReichsparteitagsgelände: Infos auf germany.travel\n\nSTEFAN HOFER\n\nBUCH ZUR WOCHE .\n\nDer größte\nReisereporter\nfeiert sein\n700. Jubiläum\n\nMarco Pole. Willmanein\nBuch lesen, das 503 Fuß-\nnoten aufweist? Nein. Soll\nman einen Reisebericht\nempfehlen, der - aus alt-\nfranzösischen und latei-\nnischen Quellen übersetzt\n-so gar nicht unseren mo-\ndernen Lesegewohnheiten\nentspricht? Eher nicht.\nUnd trotzdem: Marco’\nPolos „Il Milione“ ist einen\nVersuch wert -vor allem\n\ndie elegant gestaltete Ju-\n\nKt\n\nE3\n\nbiläumsausgabe anlässlich : -\n\ndes 700. Todestages (am\n8. Jänner 1324) des vene-\nzianischen Kaufmanns. _\nDen Originaltitel hat der\nManesse Verlag in der\nÜbersetzung belassen, mit\ndem Untertitel „Die Wunde\nder Welt“. Dieser trifft den\nKern: Wenn von sagenhaf-\n\nberichtet wird, verschwim-\n\n»\n\nmen die Grenzen zwischen\n\nBericht und Fabulierkust.\nDas sorgt beim Lesen für\nSchmunzeln und: Ver-\n\nWunderung. Im Nachwort :\n\nwird auch onen.\nFremden\n\ndem\nchen: „Wenn Mao fi\nüber seine Gastgeber\n\nDistanz.“ Buchungsplatt-\nformen hätten MIO”\ngernealsGast. 4 era\n\nPOIO\n\nIL MILIONt\n\nLIE WUNDER DER *\n\n® “\n\nLie\n\nx\nRER\nU\n\n7,\n\nMarco Polo:\n\n„I Milione -\n\nDie Wunder der Welt“\nManesse Verlag.\n\n432 Seiten. 47,50 Euro\n\nschreibt, wählt er mit ganz “\n"wenigen Alsnalimen eine\nfreundliche, respektwalle','\n',char(10)),'reise_nuernberg_2026-03-20_00/image.webp','reise_nuernberg_2026-03-20_00/thumb.jpg',89.5,0,'manual','2026-03-21 06:32:12','2026-03-21 10:15:35','["Nürnberg"]','["germany.travel"]',NULL,NULL,NULL);
INSERT INTO articles VALUES(14,'kochen_2026-03-20-0022.tif','2026-03-21','Kurier Freizeit',NULL,'38','Früher öfter Gast, geht es nach zwei Jahren Pause mal wieder ins Cafe Drechsler','Der Artikel beschreibt die Erfahrung eines Kellners, der wieder ins Café Drechsler in Wien zurückkehrt. Er beschreibt die Situation, dass das Café trotz der Pause immer noch besetzt ist, aber der Kellner schnell einen Platz findet. Der Artikel wechselt dann zu einem Restaurantbesuch, wo der Kellner die Qualität und Zubereitung der Speisen lobt, aber auch kritisiert, dass die Wartezeit unverhältnismäßig lang ist und dass Servietten erst nach der Bitte nachgereicht werden. Der Artikel endet mit einer Kochinspiration für Ingwer, der als Würze für Sushi und Maki-Teller verwendet werden kann.','Plus/Minus','["Kaffee", "Restaurantkritik", "Wartezeit", "Ingwer"]',replace('Früher öfter Gast, geht es\nnach zwei Jahren Pause\nmal wieder ins Cafe\nDrechsler (Linke Wienzeile\n22, Wien 6). Alles scheint\nbesetzt. Doch ein junger\nKellner ist sofort bemüht,\neinen Platz zu finden - ob-\nwohl es nur um einen\nschnellen Espresso geht.\nAn der Bar wird er fündig.\n„Hallo Agnes‘, grüßt dort\ndie Chefin. Wie schön,\nnach so langer Zeit weiß\nsie noch den Namen eines\nganz normalen Gasts.\n\nZum Abendessen ins Gan-\nko Il (Heinrichsg. 6, Wien I).\nQualität und Zubereitung\nunserer Speisen sindtop.\nDoch einiges ist bemer-\nkenswert: Die Wartezeit im\nhalb leeren Lokal auf Essen\nund Trinken ist- für alle im\nLokal - unverhältnismäßig\nlang. Wir bekommen\nPapierschürzen, aber dass\nServietten erst nach unse-\nrer Bitte nachgereicht wer-\nden -an allen Tischen -\nmüsste nicht sein. Ebenso\nverzichtbar: Mineralwasser\naus Pfastikflaschen. Nach-\nbessern wär gut.\n\nSCHAUM\nROLLCHEN\n\nZUTATEN\n\n1 Packung Blätterteig\n\n1 Becher Schlagobers\n\n1 Packerl Vanillezucker\nStaubzucker\n\nButter zum Einstreichen\n\nDu brauchst:\nMini-Schaumrollenformen,\nSchüssel, Schneebesen,\nDressiersack, 1 Stunde\n\nAb8 Jahren: Hier lass dir helfen!\n\n—— KOCH-INSPIRATION ——\n\nINGWER, UNGEFÄRBT\n\nit Ingwer lässt sich die kalte Jahreszeit hervorragend\n\n| \ / | überstehen: Feine Schärfe verleiht Speisen Würze, als\nheiße Limonade mit Honig vertreibt er Erkältungen.\nEingelegt macht er als (meist) rosafarbenes Beiwerk jeden Su-\nshi- oder Maki-Teller erst vollständig. In Japan wird das „Gari“\ngenannt, die Farbe stammt von rosa Farbpigmenten junger Ing-\nwerwurzeln. Bei älteren wird dies durch Zugabe von Farbstoff\nwie etwa Rote Rüben erreicht. Geschmacklich macht rosa oder\nweiß jedenfalls keinen Unterschied. Bei Sternekoch Bei Paul tvid\nbleibt er weiß: 100 g Ingwer schälen, in möglichst feine Schei-\nben schneiden und 1 Minute kochen. Abseihen und in ein Ein-\nmachglas geben. 120 mi Reisessig (oder anderer heller Essig)\nmit 90 g Zucker und 25 g Salz aufkochen und rühren, bis sich\nder Zucker aufgelöst hat. Über den Ingwer gießen und ver-\nschließen. Vor dem Servieren 1 Tag stehen lassen. Gekühlt und\nverschlossen bis zu 4 Wochen haltbar. Von Ingrid Teufl\n\nAus: Paul ivil, Vegetarisch, DK-Verlag, 42,50 € gebunden)\n\n——-  KINDERLEICHT —— ‘)\nSchalte das Backrohr auf 180 °C. Streiche\n\n. die Förmchen mit Butter ein. Entrolle den ,\n\n(noch kalten!) Blätterteig und schneide ihn Womit kann\n\nquer in I cm breite Streifen. ich die\nWickle die Teigstreifen leicht überapr  Aöllchen noch\npend auf die Förmchen, lege sie auf ein fü ren?\n\nmit Backpapier ausgelegtes Backblech. Klassisch werden sie\n\n©) Backe die Rollen mit Heißluft 15-20 mit einem Schaum aus\n\nMinuten. Nimm sie aus dem Ofen, lasse Zucker und Eiweil\nsie überkühlen und ziehe sie behutsam mit gefüllt, es gibt auch\n\nleichter Drehung von den Formen. # fertige Schaumrollen-\nSchlage Obers samt Vanillezucker Füllungen Iz. B.\nbis es fest ist. Fülle es in einen Dressier- Dr. Oetker).\n\nsack, spritze es in die Röllchen. Von Heidi Strobl\n\nAnzuckern. Sofort servieren. Ullikocht.at','\n',char(10)),'kochen_2026-03-20-0022/image.webp','kochen_2026-03-20-0022/thumb.jpg',91.0,0,'manual','2026-03-21 07:33:40','2026-03-21 10:05:19','["Linke Wienzeile", "Heinrichsg.", "Wien I"]','["ullikocht.at"]',NULL,NULL,'Plus/Minus');
INSERT INTO articles VALUES(19,'plusminus_2026-03-20-0001.tif','2026-03-21','Kurier','2023-04-01','Wirtschaft 7','Im vom Heurigen zum Restaurant umgestalteten Stuttnerhof (Josef-Dabsch-Str. 9, Bisamberg) passte bei unserem ersten Besuch noch so einiges nicht.','Der Kurier berichtet über einen Besuch bei einem Restaurant, das von einem Heurigen in ein Restaurant umgewandelt wurde. Die Besucher hatten Missverständnisse bei den Bestellungen und erhielten eine Gutschein über 100 Euro.','Plus/Minus','["Restaurant", "Besuch", "Gutschein"]',replace('; AUFGE TISCHT\n\nKüchen\n\nFORMSCHÖN\n1990 entworfen, zum\n70. Geburtstag von Cor\nUnum wieder im Sorti-\nment: Jede Teekanne ist\nein Einzelstück und be-\nsticht durch ihre mar-\nkante Form. 135 €.\nVon Cor Unum\n\nPRICKELND\nIn seiner edlen Messing-\noptik ist der Wassersprud-\nler „Brus“ nicht nur prak-\ntisch, sondern macht sich\nauch gut auf Arbeitsflä-\nche oder Tisch. 212,99 €\n\nVon Stelton\n\nPARTYTIME\nSo wird jedes Essen zur\ngelungenen Party! Die\nbunten Luftballon-Ser-\nviettenringe sorgen für\nStimmung. 17,90 Euro.\nVon Peleg Design\n\nAUSGESUCHT VON\nINGRID TEUFL\n\nPlus & MINUS\n\nIm vom Heurigen zum Res-\n\ntaurant umgestalteten Stutt-\n\nnerhof (Josef-Dabsch-Str. 9,\nBisamberg) passte bei unse-\nrem ersten Besuch noch so\neiniges nicht. Missverständ-\nnisse oder Unachtsamkeiten\n\nbei den Bestellungen trübten\n\neinen kulinarisch eigentlich\nerfreulichen Besuch. Auf\nunsere Mail, in der wir da-\n\nrauf hinwiesen, bekamen wir\n\nvom Stuttnerhof nicht nur\neine überaus freundliche\n\nAntwort, sondern auch einen\n\nGutschein über 100 Euro!\n\nDie Roof-Top-Bar im Hotel\nGaläntha (Esterhazyplatz 3)\nin Eisenstadt öffnet um 16 Uhr\nund vergibt Timeslots von bloß\n1,5 Stunden. Wir sind eine Grup-\npe von sechs Personen und kom-\nmen gleich zu Beginn, um uns\ngemütlich unterhalten zu kön-\nnen. Die Bar ist leer. Auf die Bit-\nte, die sehr laute Musik etwas\nleiser zu stellen, erklärt uns der\nKellner, dass dies keinesfalls\nmachbar sei, der Apparat sei\nnicht zu verändern. Schade, dass\nwir uns beim Plaudern gegen-\nseitig anbrüllen mussten.\n\nHaben auch Sie etwas für Plus/Minus erlebt?\nSchreiben Sie uns unter freizeit@kurler.at\n\nKinder LEICHT\n\nPOPCORN\n\nZUTATEN\n\n1-2 Kolben Popcornmais\n(gibt''s z. B. bei\nMorgenrot/Wien 17 und im\nSaftladen/Poysdorf)\nMaiskeimöl\n\nSalz\n\nDu brauchst:\nTopf, Schüssel, 20 Minuten\n\nAb 10 Jahren\n\nVON HEIDI STROBL\nheidi-strobl.at\n\nLöse die Körner mit den Fingern vom\nMaiskolben ab. Entferne kleine Pflanzen-\nhärchen und -brösel. Alternativ: Kaufe fertig\nabgerebelte Popcornmaiskörner.\nGib 3 EL ÖL in einen geräumigen Topf.\nStreue die Maiskörner hinein, schwenke\nsie, sodass alle mit Öl bedeckt sind. Erhitze\nden Topf, bis das Öl leicht zu blubbern be-\nginnt, dann setze den Deckel auf.\nDer Mais beginnt nach 2-3 Minuten zu\n„poppen”. Schüttle den Topf immer wie-\nder mal durch, ohne den Deckel zu öffnen.\nWird es still im Topf, sind alle Körner ex-\nplodiert. Hebe den Deckel vorsichtig ab.\nSalze das Popcorn, leere es in eine Schüssel.','\n',char(10)),'plusminus_2026-03-20-0001/image.webp','plusminus_2026-03-20-0001/thumb.jpg',93.5,0,'auto','2026-03-21 09:46:45','2026-03-21 09:46:45',NULL,NULL,NULL,NULL,'Plus/Minus');
INSERT INTO articles VALUES(20,'plusminus_2026-03-20-0002.tif','2026-03-21','Kurier',NULL,'42','Die große Pizzaschaufel','Der Artikel beschreibt eine Pizzaschaufel, die mit einem extra langen Stiel aus Akazienholz aus dem Ofen geholt wird. Die Pizzaschaufel ist mit einem rosa Salzblock auf jeder Tafel und mit Obst und Gemüse auf dem Grill oder im Ofen gewürzt. Der Artikel ist Teil der Rubrik Plus/Minus.','Plus/Minus','["Pizzaschaufel", "Salzblock", "Grill", "Ofen", "Küche"]',replace('ı AUFGE IISCHT\n\nPLATZSPAREND\nDie große Pizzaschaufel\nholt jeden Teigfladen\nzuverlässig aus dem\nOfen - der extra lange\nStiel aus Akazienholz\nlässt sich sogar einklap-\npen. 32,% €.\n\nVon Silberthal\n\nDer rosa Salzblock ist\nnicht nur ein Blickfang\nauf jeder Tafel. Am Grill\noder im Ofen platziert\nwürzt er auch noch mit\nzarter Salznote. 39,95 €\n\nVon KitchPro\n\nERHÖHT\nObst und Gemüse sind\nzu schade für Schalen.\nIhnen gebührt ein\n\nPodestplatz. 107 €.\nVon Formfollows\n\nAUSGESUCHT VON\nINGRID TEUFL\n\nPlus & MINUS\n\nNach einer Wanderung kehren\nwir im „Kühstein.haus” (Küh-\nsteingraben 14, Langenlois)\n\nein. Wir werden mit regionaler\n\nKüche belohnt. Das Team\nsetzt auf Klassiker wie\nSchweinsbraten und Sur-\nschnitzel, ergänzt durch Heu-\nrigen-Schmankerl und Spezia-\nlitäten wie Kalbsleber oder\nvegetarische Krautrouladen\nauf Kürbispüree. Dazu gibt''s\nKamptaler Spitzenweine, die\nden Charakter der Gegend ins\n\nGlas bringen. Ein Ort, an dem\n\nman schmeckt, wo man ist.\n\nAn einem bitterkalten Tag mit\nFreunden ins MAK, neben Hel-\nmut Lang gibt''s genug weitere\nAusstellungen zu sehen, wir be-\nkommen Lust auf einen Kaffee\nfür zwischendurch. Im MAK-Cafe\nmüssen wir leider feststellen,\ndass der gemütliche Salon nur\nfür Gäste ist, die auch etwas es-\nsen wollen, während man seinen\nCappuccino im zugigen Schlauch\nvor der Tür nach draußen zu sich\nnehmen muss. Dass die henkello-\nsen Tassen allesamt am Rand an-\ngeschlagen waren, passt zu unse-\nrer Stimmung. Kalt erwischt.\n\nHaben auch Sie etwas für Plus/Minus erlebt?\nSchreiben Sie uns unter freizeit@kurier.at\n\nKinder LEICHT\n\nVEGANE KNOBLAUCH-MAYO\n\nZUTATEN\n\nAbtropfwasser eines kleinen\nGlases Kichererbsen (ca 50 ml)\nYTL englischer Senf\n\n1 TL Zitronensaft\n\nCa. 200 ml Raps- oder\nSonnenblumenöl\n\n1-2 Knoblauchzehen, Salz\n\nDu brauchst:\nMixer, 10 Minuten\n\nAb 8 Jahren: Hier lass dir heifen! 5\n\nVON HEIDI STROBL\nheidi-strobl.at\n\nLege ein Sieb auf eine schmale Schüssel,\nschütte die Kichererbsen hinein und lasse\nsie gut abtropfen. Verwende die Kichererb-\nsen z.B. für Salate oder Hummus.\nSchäle den Knoblauch, viertle ihn. Gib\nSenf, Knoblauch und Zitronensaft zum\nKichererbsenwasser, mixe es mit einem\nHandmixgerät oder Stabmixer luftig auf.\nJetzt brauchst du Hilfe: einer hält die\nSchüssel, einer gießt nach und nach ÖL\ndazu und mixt es ein. Zuerst tropfenweise,\ndann in einem dünnen Strahl #\nDie Mayonnaise wird immer dicker\nund fester. Schmecke sie mit Salz und\nZitronensaft ab.','\n',char(10)),'plusminus_2026-03-20-0002/image.webp','plusminus_2026-03-20-0002/thumb.jpg',92.5999999999999943,0,'manual','2026-03-21 09:49:45','2026-03-21 10:03:26','[]','[]',NULL,NULL,'Plus/Minus');
INSERT INTO articles VALUES(21,'kulinarik_2026-03-20-0015.tif','2026-03-21','Kurier','2023-04-01','3','Lebzeltereien','Der Kurier berichtet über verschiedene Lebkuchenhersteller in Wien, Mariazell und Mödling. Die Artikel sind Teil der Rubrik "Plus/Minus", die kurze positive oder negative Lokalkritiken enthält.','Lokales','["Lebkuchen", "Wien", "Mariazell", "Mödling"]',replace('TOP FÜNF\n\nLebzeltereien\n\nSind Lebkuchen ein aussterbendes Nischenprodukt?\nDefinitiv nicht, die heimische Lebzelter-Szene erfreut\nsich bester Gesundheit. Zum Beispiel hier:\n\nVon Florian Holzer\n\nWien gibt es eine Lebkuchenfabrik: Robert\n\nKammerer führt sie in dritter Generation, die\nManufaktur wirkt, als wäre die Zeit stehen geblie-\nben. Aber: Seit Corona gibt''s auch einen Shop, viele\nder Zutaten sind bio, die Qualität ist erstklassig.\n\nWien 20, Dammstr. 39, 01/330 75 33,\nMo-Do 7-16, Fr 7-13, wiener-lebkuchen.at\n\n1 WIENER LEBKUCHEN Kaum zu glauben, in\n\nder kleinen Traditions-Lebzelterei Kerner ist\n\nPirker der einzige Lebkuchenbäcker in Maria-\nzell. Und einer der erfolgreichsten und größten in\nganz Österreich. Pirker-Lebkuchen glänzen mit\nZuverlässigkeit, sind an vielen Orten erhältlich.\n\n8630 Mariazetl, Wiener Str. 9, 03882/21790,\nDi-Sa 10-14, lebkuchen-pirker.at\n\n) ri Nach dem bedauernswerten Ende\n\n— KINDERLEICHT —\nRACHENZENTNER Eine kleine, uralte Lebzel- 5 Schalte das Backrohr auf 180 ‘C. Wasche\nterei in Mödlings Altstadt, bei der Handwerk- OFENGEMUSE L die Süßkartoffel gründlich unter fließen-\n\nlichkeit und über 200 Jahre alte Familienre-\nzepte hohe Priorität genießen. Gearbeitet wird mit\nbesten Zutaten, nach alter Tradition bekommt man\nim Geschäft auch Honig und Kerzen.\n\n2340 Mödling, Herzogg. 4, 0676/648 68 90, Mo-Sa\n9-12.30, Mo-Fr 14-18, lebzelterei-rachenzentner.at\n\nZUTATEN dem Wasser. ‘Halbiere sie längs, dann\nl große Süßkartoffel schneide sie in möglichst gleichmäßig\nEine Handvoll Kohlsprossen schmale Spalten.\nOlivenöl Putze die Kohlsprossen: schneide den\nSalz Stielansatz weg, zupfe ggf. welke Blätter\nev. ein Ästchen Rosmarin weg, halbiere die Kohlsprossen. #\nVerteile das Gemüse auf einem mit Back-\n\nLEBZELTEREI ILLECKER Tradition ist bei der Du brauchst: Backblech, papier ausgelegtem Backblech. Beträufle\nKonditorei Illecker nicht so das Thema, denn Backpapier, 30 Minuten alles mit Olivenöl, streue Salz darüber, mi-\nder Betrieb wurde erst 1985 gegründet. Aber sche alles mit den Händen gut durch.\ndafür sind es hier Kreativität und Vielfalt, mit denen Backe das Gemüse 15-20 Minuten mit\ndie Lebkuchen beeindrucken: Hohe Pätisserie- Heißluft. Nimm es heraus, iss es heiß, am\nKunst trifft Pfefferkuchen-Tradition. Ab 11 Jahren: Hier lass dir helfen! W besten mit einem Sauerrahm-Dip.\n\n4591 Molln, Hafnerstr. 7, 07584/2021,\nDi-So, Fei 8.30-18, konditorei-iltecker.at\n\nBrauche ich Feste, relativ gute\nPEINTNER Die Konditorei Peintner gilt als ers- Süßkartoffeln nicht Beeren en u 5\nte Adresse, wenn es um Lebkuchen im Westen o zu schälen? Stellen solltest du z\ngeht. Die Innsbrucker backen ihre köstlichen allerdings wegschneiden. E\nLebkuchen-Quadrate auch als Weihnachts-Präsen- Das gilt übrigens auch für F\nte für allerlei Firmen, kein Wunder, sie sind köstlich, Erdäpfel (da musst du auch 5\nfiaumig und nicht zu süß lin Wien bei Die Cafetierel. auf grüne Stellen achten s\n6020 Innsbruck, Burggraben 4-6, 0512/597 29 50, Von Heidi Strobl und sie wegschneiden). &\nMo-Sa 9-18, konditorei-peintner.at Ulikocht.at 3\n\n44 | frazst.at','\n',char(10)),'kulinarik_2026-03-20-0015/image.webp','kulinarik_2026-03-20-0015/thumb.jpg',89.7999999999999971,0,'auto','2026-03-21 10:35:31','2026-03-21 11:10:04',NULL,'["ullikocht.at"]',NULL,NULL,'freizeit.at');
INSERT INTO articles VALUES(22,'kulinarik_2026-03-20-0016.tif','2026-03-21','Kurier','2023-04-15','39','Kulinarik','Dieser Artikel enthält Rezepte für Knödel und Marillenröster. Die Knödel werden aus gekochten Erdäpfeln hergestellt, während der Marillenröster mit entkernten Marillen, Zucker und Vanillezucker zubereitet wird.','Ernährung','["Knödel", "Marillenröster", "Erdäpfel", "Zucker", "Vanille"]',replace('FOTO: ANDREA KNURA\n\nKULINARIK\n\nfür 12 Knödel kühlen lassen. Für den Marillenröster die ent-\n\nZUTATEN 1 Die Erdäpfel kochen, noch heiß schälen, aus-\nkernten Marillen mit Wasser, Zucker, Vanille-\n\nFür den Teig: zucker und Zitronensaft aufkochen, abkühlen lassen.\nV kg gekochte, gepresste, kalte Dj kühlten Erdäpfel durch e Erda\nR . € ausgekühlten Erdäpfe urch eine Erdäp-\nErdäpfel iz. B. Sorte Ditta ) felpresse drücken, mit den restlichen Zutaten\n1EEi, 1 EL weiche Butter vermischen und zu einem Seidigen Teig kneten.\n250g griffiges Mehl\n. Den Teig in 12 Stücke teilen, Die Stücke flach-\nPrise Salz R Enuraile a: .\n. drücken, jeweils eine Marille drauflegen, den\n12 Marillen Teig rundherum andrücken und rund formen\nDie Knödel in kochendes Salzwasser einlegen und\nFür die Mohnbröset: @a. 15 Minuten leicht kochen lassen. Wenn die Knödel\n709g Semmelbrösel an der Oberfläche schwimmen, sind sie fertig.\n\nTEL Feinkristallzucker anrösten, die Knödel darin wälzen. Mit Maril-\n\n70 g Graumohn, gequetscht lenröster anrichten,\nmit Staubzucker bestreuen.\n\n50 g Butter 1 Brösel und Graumohn in Butter und Zucker\n\nFür den Marillenröster:\n1 kg entkernte Marillen\netwas Wasser, etwas Zitronensaft\n\n3 EL Zucker, 1 TL Vanillezucker Die Mohnwirtin kocht,\n\nRosemarie Neuwiesinger,\nEigenverlag, 29€\n\nJede Woche ein Rezept - ausgesucht und empfohlen von Heidi Strobl\n\nAufwand: @80 Zubereitungszeit: 1,5 Stunden Preis: 8@00 Kalorien: ca. 320 kcal/Knödel\n\nfreizeit.aı | 39','\n',char(10)),'kulinarik_2026-03-20-0016/image.webp','kulinarik_2026-03-20-0016/thumb.jpg',86.5999999999999943,0,'auto','2026-03-21 10:37:11','2026-03-21 11:06:56',NULL,NULL,NULL,NULL,'freizeit.at');
INSERT INTO articles VALUES(23,'kulinarik_2026-03-20-0017.tif','2026-03-21','Kurier','2023-08-15','Wirtschaft 7','FISCHHEURIGER','Der Artikel beschreibt die Biologische Fischzucht und den Biofisch-Shop von arc Mößmer in Wien. Er nennt die Produkte wie Steckerifisch, Räucherforelle, Fischburger und Raritäten wie knusprig panierter Lachs-Milchner. Der Artikel beschreibt auch die Atmosphäre und den Service des Biofisch-Shop.','Plus/Minus','["Biologische Fischzucht", "Biofisch", "Wien"]',replace('ILLUSTRATION: BIRGITTA HEISKEL; FOTOS: GILBERT NOVY (2), BOFISCH GMBH, ISTOCKPHOTO.COM\n\n—— SALZ & PFEFFER ——\n\nFISCHHEURIGER\n\narc Mößmer ist ein interessanter Mann:\n\nNicht nur, dass er im nördlichen Wald-\n\nviertel einen riesigen Fischteich biologisch\n\nbewirtschaftet. Er hat in den 90ern - als\n\nLehrender an der Wiener Boku - die biolo-\ngische Fischzucht quasi erfunden, entwickelte damals die\nRichtlinien, wie biologische Tierzucht bei Fischen aussehen\nsollte. Und er versucht, dieses Thema auch an die Kunden\nheranzubringen: Seine Firma „Biofisch“ verkauft auf fünf\nWiener Märkten, in der Firmenzentrale in Hetzendorf be-\ntreibt er einen gut sortierten Biofisch-Shop und ein Bistro.\nUnd im Sommer auch den legendären „Fischheurigen“: Im\nFreibereich eines ehemaligen, riesigen Balkan-Hochzeitslo-\nkals wurden ein Foodtruck und Hotzbankerin aufgestellt,\nSchirme schützen vor Sonne oder kleinen Regengüssen.\nBestseller ist natürlich, wie könnte es anders sein, der Ste-\nckerifisch. Saftig, zart, die Haut über Holzkohle knusprig ge-\nröstet - und zwar von heimischer Bio-Forelle oder -Saibling,\nnicht tiefgefrorene Nordsee-Makrele wie in den meisten Fäl-\nlen (22,50 €). Es gibt aber noch viel mehr, eins besser als\ndas andere: Räucherforelle, Fischburger, Fisch & Chips oder\nRaritäten wie knusprig panierter Lachs-Milchner, grandios.\nUnd am Vorspeisenteller spielt sich’s überhaupt ab: Ver-\nhackerts vom Saibling, Lachsforellen-Tatar, Pulled Lax, Saib-\nlings-Ceviche, Räucherfisch-Aufstrich und ein bisschen Kim-\nchi aus Ottakring auch noch (15,90 € für 2 Pers.). Herzliche\nAtmosphäre, ein paar großartige Weine, unmittelbar neben\nder Schnellbahn und sogar ein paar Parkplätze gibt''s. Per-\nfektes Soemmerprogramm. Von Florian Holzer\n\nWien 12, Hetzendorfer Str. 59, 0699/171 89 606, Do 17-22,\nFr 15-22, Sa 11-22, biofisch.at\n\nSCHANIGARTEN: JA - HUNDE: JA - KARTENZAHLUNG: JA\n\nZum Lokalfinder:\n:\n\nESSEN\n33/30\n\n©\n\nSERVICE\n910\n\n©\n\nWEINKARTE\n12/15\n\n©\n\nAMBIENTE\n19,25\n\nGESAMT\n\n75/100\n\nTOP FÜNF\nSommer-Pop-ups\n\nPop-ups sind aus der österreichischen Gastroszene\nnicht mehr wegzudenken. Diese hier überzeugen mit\nLocation, Idee, Programm und gutem Essen!\n\nVon Florian Holzer\n\nGUGUMUCK GARTENBAR Die Gartenbar des\n\nSchneckenzüchters Andreas Gugumuck findet\n\nheuer zum vierten Mal statt und ist daher fast\nschon ein Klassiker: idyllischer Pavillon in den\nFeldern, tolle Drinks, großartige Snacks {nicht nur\nmit Schnecke), Stimmung ohne Ende.\n\nWien 10, Rosiwalg. 44, 0676/365 36 43,\nDo, Fr 15-22, Sa, So 11-22, gugumuck.com\n\nRuckser übernahm das malerische Thaya-\n\nStrandbad in Drosendorf. Und sorgt für Pro-\ngramm: Sommerkino, „Thayabar” und den „kulina-\nrischen Montag”, darunter mit den „Wirtshaustöch-\ntern” Sylvia Petz und freizeif-Autorin Heidi Strobl.\n\n2095 Drosendorf, Sebastian-Kneipp-Pl. 1, 0664/31 1\n14.84, 11.,12., 14. 8. ab 18.30, thaya-strand-bad.at\n\nj ) DIE WIRTSHAUSTÖCHTER Autorin Elisabeth\n\nPALAIS FREILUFT Das „Palais Freiluft” im\n\nPark des Palais Auersperg geht heuer in die\n\nzweite Runde. Bis Anfang September kann\nman hier in Park-Ambiente Champagner bei\n„Dosage” schlürfen, Sushi, Thum-Schinken oder\nSmashed Burger naschen oder bei „&flora” essen.\n\nWien 8, Trautsong. 1B,\nMo-Sa 16-23 (bei Schönwetter), freiluft.co.at\n\nZUPPA SOMMERFRISCHE Im historischen\n\nLedermayerhaus veranstaltet die Künstlerin\n\nMaria Mayrhofer ein Sommerfrische-Pop-up:\nmit Kunst, Mode und vor allem mit tollem Essen\nihrer Schwerster Heidi Mayrhofer, der besten Take-\naway-Gastronomin Wiens.\n\n4866 Unterach/Attersee, Hauptstr. 12, 4.-15. 8. 16-22\n(bei Schönwetter), instagram.com/zuppawien/\n\nOTTO AM BERG Max Stiegl lässt wieder von\n\nsich hören: Vor Jahren entwickelte er ein\n\nKonzept zur Nutzung des gerade revitalisierten\nOtto-Wagner-Spitals am Steinhof. Erster Schritt:\nEine Pop-up-Kooperation mit XO Beef, das heißt:\nSmashed Burger-Foodtruck im Jugendstil-Ambiente.\n\nWien 14, Baumgartner Höhe 1, Pavillon 24,\nFr-So 11-21, instagram.com/ottoamberg/\n\nfrazeit.at | 37','\n',char(10)),'kulinarik_2026-03-20-0017/image.webp','kulinarik_2026-03-20-0017/thumb.jpg',91.5999999999999943,0,'auto','2026-03-21 10:40:09','2026-03-21 11:06:21',NULL,NULL,NULL,NULL,'Plus/Minus');
INSERT INTO articles VALUES(24,'kulinarik_2026-03-20-0018.tif','2026-03-21','Kurier','2023-04-01','Wirtschaft 7','Maria und Josef - ein neues Lokal am Dienstagabend gesteckt voll ist','Das Lokal „Maria und Josef” in Wien bietet eine moderne Atmosphäre mit schwarzer Marmorbar, geschmackvollem Mobiliar und gedämpfter Beleuchtung. Die Karte ist mediterran-orientalisch-asiatisch und die Vinothek im zweiten Raum ist in einer historischen Apotheke untergebracht. Die Preise sind nicht verschreckend und die Portionen sind mächtig.','Plus/Minus','["Lokal", "Wien", "Karte", "Preise", "Service"]',replace('ILLUSTRATION: BIRGITTA HEISKEL; FOTOS: GILBERT NOVY (2), RITA NEWMAN, VIENNA VISITAS PHOTOCRAPHY\n\n—— SALZ & PFEFFER ——\n\nMARIA UND JOSEF\n\nenn ein neues Lokal am Dienstag-\n\nabend gesteckt voll ist, dann macht\n\nda jemand einiges richtig: Das „Maria\n\nund Josef“ bietet mit schwarzer Mar-\n\nmorbar, geschmackvollem Mobiliar,\ngedämpfter Beleuchtung, Kunst und einer gelungenen Farb-\ngebung (ganz ohne die inflationären Dschungel-Tapeten) in-\ntime Atmosphäre pur. So sehen hippe Lokale normalerweise\nin London oder Manhattan aus, in Wien nicht. Auch die Karte\nwirkt sehr interessant: Eine mediterran-orientalisch-asiati-\nsche Mischung, die neugierig macht - und deren Preise nicht\nverschrecken. Nicht zuletzt ist da noch die Vinothek im\nzweiten Raum, untergebracht in Regalen einer historischen\nApotheke, das macht die Sache niederschwellig. Hinter dem\ngelungenen Konzept steht Shahab Jahanbekloo, der in Wien\nschon ein paar tolle Lokale hatte, mit dem „Engel“ etwa das\nbeste Naschmarkt-Lokal seiner Zeit. Vier Jahre widmete er\nder Renovierung und Umwidmung eines früheren Interieur-\nGeschäftes, eine Mühe, die sich lohnte. Auch für uns Gäste.\nDie Ofen-Melanzani mit grüner Tahina, Kichererbsensalat\nund Granatapfel ist großartig (9,20 €), der sautierte Chico-\nr&e mit Brie und Walnüssen klang ein bisschen interessanter,\nals er dann war (9,80 €). Die geschmorte Lammschulter mit\nPistazien wird „pulled“ und auf vier Salatblättern serviert,\nköstlich (16,80 €), Marzipan-Baklava mit Safraneis auch sehr\ngut (6,80 €). Die Portionen sind mächtig, „Sharing“ lautet die\nIdee dahinter. Einziger Nachteil des erfolgreichen Konzepts:\nWenn das Lokal überrannt wird, geraten Küche und Service\nmitunter ins Schwimmen. Von Florian Holzer\n\nWien 6, Rahlg. 1, 01/946 17 75, Di-Sa 16-24,\nmariaundjosefwien.at\nSCHANIGARTEN: JA - HUNDE: JA - KARTENZAHLUNG: JA\n\nESSEN\n39:30\n\nSERVICE\n7:10\n\n©\n\nWEINKARTE\n13/15\n\n©\n\nAMBIENTE\n\nGESAMT\n83.100\n\nTOP FÜNF\nSpeakeasy-Bars\n\nVor 100 Jahren, während der Prohibition in den USA,\nwaren „geheime” Speakeasy-Bars faktische Notwen-\ndigkeit. Heute sind sie der Bar-Trend schlechthin:\n\nVon Florian Holzer\n\nFITZCARRALDO Die jüngste und aktuell wohl\n\nauch originellste Hinterzimmer-Bar Wiens: Der\n\nEingang versteckt sich hinter einem Getränke-\nautomaten. Wer ihn bedient, dem öffnet sich die Tü-\nre in die schillernd bunte Dunkelbar von Influencer\nHenk Ge und Bar-Profi Sammy Walfisch.\n\nWien 7, Neubaug. 38, Di-Do 18-1, Fr, Sa 18-2,\nfitzcarraldo-bar.com\n\nTHE CHAPEL Das Lokal in Westbahnhof-Nähe\n\nwar immer schon: Jahrzehntelang befand sich\n\nhier das Nachtbeist „Mozart”. Beim Umbau\nvor ein paar Jahren wurde die originelle Hinterzim-\nmer-Bar instatliert. Die Eingangstüre verbirgt sich\nhinter einem Bilderrahmen.\n\nWien 15, Haidmannss. 8, 0681/815 61 233, Di-Do\n18-1, Fr, Sa 18-3, facebook.com/thechapelbarvienna/\n\nKRYPT. Mit Tageslicht muss man in der\n\nCocktail-Krypta nicht rechnen: Mit dem\n\nAufzug geht''s in die Tiefe, dort wird in weitläu-\nfigen Ziegelgewölben dann den alkoholischen\nMischgetränken und der Musik gefrönt. Mittelding\naus Bar und Club.\n\nWien 9, Bergg. 5, Mi, Do 19-1, Fr, Sa 20-3,\n\n-krypt.bar\n\nTÜR 7 Einer der frühesten Vertreter der\n\nSpeakeasy-Welle in Wien: Absolut gar nichts\n\nweist in der dunklen Buchfeldgasse auf die\nBoutique-Bar hin, erst nach Betätigung der Klingel\nöffnet sich die Türe der intimen 35-Personen-Bar.\nReservierung ist absolut notwendig.\n\nWien 8, Buchfeldg. 7, 0664/546 37 17,\nMo-Fr ab 21, tuer7.at\n\nTHE HIDDEN CLUB Die im September 2021\n\ngestartete Geheim-Bar des Szenegastrono-\n\nmen Martin Ho zeigt sich als „unschuldiges”\nSouterrain-Süßßwarengeschäft. Hinter einer ver-\nsteckten Türe dann eine riesige, aus einem Droge-\nriemarkt geformte Untergrundbar in rotem Samt.\n\nWien 7, Mariahitfer Str. 36, Fr, Sa ab 23,\ndotsgroup.eu/hidden-club/\n\nfreizest.at | 47','\n',char(10)),'kulinarik_2026-03-20-0018/image.webp','kulinarik_2026-03-20-0018/thumb.jpg',92.2999999999999971,0,'auto','2026-03-21 10:43:48','2026-03-21 11:06:21',NULL,NULL,NULL,NULL,'Plus/Minus');
INSERT INTO articles VALUES(25,'kulinarik_2026-03-20-0020.tif','2026-03-21',NULL,NULL,NULL,'Steirischer Pommes frites in Österreich','Ein steirischer Gastronom, Franz Grossauer, hat Pommes frites in Österreich anbieten wollen. Er hat ein Konzept aus Deutschland übernommen und es in Österreich weiterentwickelt. Die Pommes frites sind beeindruckend und werden mit verschiedenen Gerichten kombiniert.','Plus/Minus','["Pommes frites", "Steirischer Gastronom", "Gourmet-Pommes"]',replace('MHLUSTRATION: BIRCITTA HEISKEL; FOTOS: JUERC CHRISTANDL, ISTOCKPHOTO.COM\n\nFRAMBURIFRIES\n\neder liebt Pommes frites. Aber: Kaum wer von uns\n\nhat schon so richtig gute Pommes frites gegessen.\n\nDafür muss man nämlich nach Flandern fahren,\n\nsich bei einem der Fritture-Standeln anstellen und\n\ndann sein blaues Wunder erleben. Franz Grossau-\ner, steirischer Multi-Gastronom, wollte die wirklich guten\nPommes aber auch in Österreich anbieten. Er studierte das\nKonzept der deutschen Kette „Frittenwerk“, die Gourmet-\nPommes im „Frites Atelier“ des niederländischen Starkochs\nSergio Herman und fragte schließlich Spitzenkoch Alexan-\nder Mayer, was er von Top Pommes frites in Österreich hal-\nten würde. Und der hielt viel davon. Grossauer bestellte also\neine fünf Meter lange High-Tech-Frittüre um 100.000 Euro\nin den Niederlanden, fand einen Weinviertler Bio-Bauern, der\nihm die passenden Erdäpfel liefert, mit Mayer wurde an Re-\nzepturen und Saucen getüftelt. Vor etwas mehr als zwei Wo-\nchen startete das Soft Opening. Und man muss sagen: Die\nPommes frites können sich sehen lassen. Schon die Basis-\nPortion nackter Pommes (Ketchup und Mayonnaise zum Sel-\nbernehmen) ist beeindruckend, da sieht man, dass das Prin-\nzip verstanden wurde (4 €). Spektakulär wird’s dann als\n\nKombination etwa mit „Backfisch“, bei dem Alex Mayer na-.\n\ntürlich auf edie Mittelstücke vom Kabeljau-Loin bestand\n(12,50 €), mit Thunfisch-Sashimi (15 €) oder mit wirklich\nausgezeichnetem Veggie-Chili sin Carne (9,50 ©).\n\nMein Highlight: der „steirische“ (geschmorte) Zwiebelrost-\nbraten (13,50 €). Dazu gibts sechs verschiedene Flaschen-\nbiere und diverse Top-Weine in der Halbflasche. Könnte sich\ndurchsetzen. Von Florian Holzer\n\nWien 1, Rotenturmstr. 16/18, So-Mi 11-22.30, Do-Sa 11-24,\ninstagram.com/framburi_fries/\n\nSCHANIGARTEN: JA - HUNDE: JA - KARTENZAHLUNG: JA\n\n37:50\n\nSERVICE\n6/10\n\n2\nWEINKARTE\n10/15\n\n©\n\nAMBIENTE\n22:25\n\nGESAMT\n\n75/100\n\nTOP FÜNF\nDo it yourself-Kurse\n\nKochkurse gibt es viele. Hier aber lemt man die\nspeziellen kulinarischen Fähigkeiten von den Profis.\nVielleicht eine Geschenk-Idee für Weihnachten ...\n\nVon Florian Holzer\n\nSCUOLA VOLANTE Alle essen Pizza, alle reden\n\nüber Pizza, alle meinen, alles über Pizza zu\n\nwissen. In der Scuola Volante - einem Spin-off\nder guten Pizzeria Disco Volante - lehren die neapo-\nlitanischen Pizzaioli, wie es wirklich geht: von Teig-\nführung bis Temperatur. Unbedingt reservieren!\n\nWien 4, Kolschitzkyg. 6, 0676/344 16 45, Sa 11,\nscuola-volante.at\n\nAUGORA Alexandra Liberda schuf hier ein\n\nKompetenzzentrum für alles Fermentierte,\n\nvon Kombucha bis Sauerbier. All das kann\nman hier auch in Kursen erlernen, darüber hinaus\nauch Käsen mit Melanie Kelnreiter oder Fleischzer-\nlegung mit Fleischermeisterin Claudia Ringl.\n\nWien 6, Stumperg. 1A, 0660/959 97 67,\naugora.at\n\nKRUSTE & KRUME 2018 eröffneten die TV-\n\nModeratorin und Slow Food Wien-Leiterin\n\nBarbara van Melle mit dem Bäcker Simon\nWöckl Wiens erstes Brotbackatelier. Hier lernt man\nnicht nur irgendein selbst gemachtes Brot zu\nbacken, sondern Brot richtig zu backen.\n\nWien 4, Heumühlg. 3/1, 0664/926 47 72,\n\nkrusteundkrume.at\n\nHAUSMAIR''S GASTSTÄTTE Herbert Hausmair\n\nist beseelter Gastwirt und leidenschaftlicher\n\nJäger. Und er veranstaltet Kurse, bei denen\nerlernt werden kann, wie man Wildbret aus dem\nBalg schlägt, zerlegt und richtig zubereitet. Mit Jän-\nner starten die Kurse wieder, Thema „Wildschwein”.\n\nWien 7, Lerchenfelder Str. 73, 0676/754 60 18,\nhausmair.at\n\nKIESBYE BIERKULTURHAUS Braukurse\n\n‚werden oft angeboten. Axel Kiesbye hat das\n\nmit den Braukursen aber mehr oder weniger\nerfunden. Er bildet Bier-Sommeliers und Braumeis-\nter aus, drei verschiedene Kurse: „Classic”, „Craft”\nund „Culinaric” kann man bei ihm buchen.\n\n5162 Obertrum, Dorfpt. 1, 0664/25341 62,\nkiesbye.at\n\nfreizeit. | 53','\n',char(10)),'kulinarik_2026-03-20-0020/image.webp','kulinarik_2026-03-20-0020/thumb.jpg',92.4000000000000056,1,'auto','2026-03-21 10:47:31','2026-03-21 10:47:31',NULL,NULL,NULL,NULL,'Plus/Minus');
INSERT INTO articles VALUES(26,'kulinarik_2026-03-20-0021.tif','2026-03-21','Kurier','2023-04-01','Wirtschaft 7','Bitzinger The Passion: Bierlokal mit moderner Küche','Der Kurier berichtet über das Bierlokal Bitzinger The Passion in Wien. Es wurde 2003 neu gestaltet und bietet ein sechsgängiges Menü abends für 149 Euro. Die Küche wurde auf international geändert, die Preise angepasst und das Lokal als Vinothek weitergeführt. Der Autor schätzt die Küche und den Service.','Lokales','["Bierlokal", "Küche", "Wiener Wald"]',replace('HLLUSTRATION: BIRCITTA HEISKEL; FOTOS: ITZINGER THE PASSION, ISTOCKPHOTO.COM\n\nEL 0)\n\nLITE Lu Bi\n.s\nwicht ’\n\n— SALZ& PFEFFER —\n\nBITZINGER THE PASSION\n\nm Jahr 2003 ließ Albertina-Direktor Klaus Albrecht\n\nSchröder die Augustinerbastei vom Architekten\n\nHans Hollein neugestalten, die Albertina per Rolltrep-\n\npe erschließen. Das wurde damals heftig diskutiert,\n\nauch, ob das Bierlokal Augustinerkeller die würdige\nBasisstation für die weltberühmte Grafiksammlung sei. Be-\ntreiber Josef Bitzinger nahm sich das jedenfalls zu Herzen,\nließ Hollein neben die Rolltreppe ein modernes Lokal na-\nmens „Cafe Atelier“ in die Bastei einfügen. Das bald aber nur\nmehr als Vinothek genutzt wurde. Nach zwanzig Jahren\nnahm Bitzinger nun einen neuen Anlauf: Das alte Hollein-De-\nsign wurde etwas adaptiert, der Name des Lokals in „Bitzin-\nger The Passion” geändert, die Küche auf „international“ ge-\ntrimmt, die Preise der heimischen Top-Liga angepasst: Das\nsechsgängige Menü abends kommt auf€ 149, das neungän-\ngige auf € 199, mittags wird ein viergängiges Business-Me-\nnü angeboten (€ 59). Dabeginnt man etwa mit einer wirklich\nguten Spargelcremesuppe mit Pilzen und (geschmacklosen)\nShrimps, dann kommen drei kleine Jakobsmuscheln mit\nTrüffelcreme auf Karottencreme, garniert wieder mit Spar-\ngel. Als Hauptspeise stehen Thunfischsteak oder Rib Eye zur\nWahl, die kleine Portion Steak ist tadellos gebraten, die in-\ntensive Sauce dazu vielleicht etwas grob. Das Apfelküchlein\nmit Vanilleeis erfreut vor allem das Auge. Wunderbar, nur ist\nes das, was die Leute - vor allem Touristen schauen herein\n- hier wollen? Nicht vielleicht Wiener Küche auf sehr hohem\nNiveau? Ich fürchte, „The Passion“ wird es gegen Do & Co,\nGuesthouse, Palmenhaus, Sacher und Cafe Mozart schwer\nhaben. Von Florian Holzer\n\nWien 1, Augustinerstr. 1, 01/533 10 26, Mi-So 12-15, 18-23,\nbitzinger.wien\n\nSCHANIGARTEN: JA - HUNDE: JA - KARTENZAHLUNG: JA\n\n40:30\n\nSERVICE\n7.10\n\nP2\nWEINKARTE\n12/15\n\n©\n\nAMBIENTE\n22/25\n\nGESAMT\n\n81/100\n\nTOP FÜNF\n\nEssen im Wienerwald\n\nBeliebtes Naherholungsgebiet, Grün-Oase, Frischluft-\nSpender Wiens, Landschaftsjuwel. Und ein Platz, wo\nman wirklich gut essen kann:\n\nVon Florian Holzer\n\nhaus wie aus dem Bilderbuch, das aber mit der\n\nZeit gegangen ist. Also wird hier Gasthaus-\nTradition wie das Sonntagsbratl vor Schopf ebenso\nhochgehalten wie saisonale Spezialitäten und\nBeachtung regionaler Produzenten.\n\n2531 Gaaden, Hauptstr. 52, 02237/7282,\nMi-Fr 10-15.30, 17.30-22.30, Sa 10-22.30,\nSo 10-21.30, zu-den-linden.at\n\n1: DEN LINDEN Ein wunderbar uriges Gast-\n\nvergangenen Jahren zum Gourmet-Paradies\n\nentwickelt, hier wird Bier gebraut, werden\nBisons gezüchtet, Käse hergestellt. Die Linde in\nLaaben gibts aber schon viel länger, nämlich über\n200 Jahre. Edel-kreative Küche mit Bodenhaftung.\n\n3053 Laaben 28, 02774/83 78, .\nMo, Di 16-23, Fr, Sa 9-22, So 11-21, linde-laaben.at\n\n) ZUR LINDE Der Wienerwald hat sich in den\n\nter. Er kochte schon in den besten Gasthäu-\n\nsern Wiens, führte lang ein Parade-Wirtshaus\nim Piestingtal, führt seit acht Jahren das malerische\nRestaurant im Golfclub Adamstal mitten im Wald.\nWunderbar bodenständige Küche mit Pfiff.\n\n3172 Ramsau, Gaupmannsgraben 21, 02764/3500 20,\nMo-So 8-20, claus-curn.at\n\nes CURN Claus Curn ist ein alter Bekann-\n\nsie eben nur im Wienerwald möglich ist: Ein\n\n100 Jahre altes Salettl-Ausflugsgasthaus, per-\nfekt renoviert, seit zwei Jahren sogar mit Zimmern.\nHausgemachte Beinfleisch-Suppe, Karotten mit\nMerguez, Gulasch vom Kritzendorfer Hochlandrind.\n\n3400 Maria Gugging, Hauptstr. 132, 02243/87 490,\nDi-So, Fei 10-22, der-waldhof.at\n\nf WALDHOF Die Location ist so malerisch, wie\n\nhäuser, in denen die ganz spezielle Wirtshaus-\n\nKultur des Wienerwaldes gepflegt wurde - mit\nregionalen Produzenten, mit sensibel gepflegten\nGasthaus-Traditionen und mit wunderbar kreativ\numgesetzten Klassikern. Ein absoluter Fixpunkt.\n3413 St. Andrä-Wördern, Obkirchbacher Str. 16,\n\n02242/62 90, Do 17-20.30, Fr, Sa 11-21,\nSo 11-18, bonka.at\n\nFa Der Bonka war eines der ersten Gast-\n\nfraizeit.aı | 43','\n',char(10)),'kulinarik_2026-03-20-0021/image.webp','kulinarik_2026-03-20-0021/thumb.jpg',91.5999999999999943,0,'auto','2026-03-21 10:51:59','2026-03-21 11:08:41',NULL,NULL,NULL,NULL,'freizeit.at');
