INSERT INTO places VALUES(1,1,'APFELBAUER','Idylle inmitten der Wiener Hausberge. Großartige Küche mit Produkten aus der Region, Spielplatz am Bach, gute Kinder-Menüs.','Ascherstr. 15','2761','Miesenbach','Österreich','02632/8244','Mi-Sa 11-21, So 11-20','www.apfelbauer.at',NULL);
INSERT INTO places VALUES(2,1,'BONKA','Ein Gasthaus, wie es im Buche steht, nur besser bekocht. Und auferdem Spielplatz, Pferde und jede Menge grüner Wienerwald.','Oberkirchbach 61','3413','Oberkirchbach','Österreich','02242/62 90','Mi-Sa 9-21, So, Fei 9-16','www.bonka.at',NULL);
INSERT INTO places VALUES(3,1,'NIERSCHER','Das Essen ist hier auf Edelheurigen-Niveau, die Atmosphäre urig, das Angebot für Kinder umso prachtvoller: Platz, Streichelzoo, Obstgarten.','Hauptstr. 190','3400','Weidling','Österreich','02243/339 33','Di-Fr 15-24, Sa, So, Fei 12-24','www.nierscher.at',NULL);
INSERT INTO places VALUES(4,1,'STOCKERWIRT','Der Familien-Klassiker. Spielplatz, kleines Biotop mit Bach, Spielzeug. Zu beachten: Kinder wollen nicht warten, der Andrang ist oft groß.','Hauptstr. 36','2392','Sulz im Wienerwald','Österreich','02238/82 590','Mi-Sa 11.30-22, So, Fei 11-21','www.stockerwirt.com',NULL);
INSERT INTO places VALUES(5,1,'BLAA-ALM','Hier können sich nicht nur die Zwerge am Spielplatz mitten auf der Alm austoben, auch Eltern bekommen alles, was eine Hütte bieten kann.','Lichtersberg 73','8992','Altaussee','Österreich','03622/71 102','Mo-So 9-24','www.blaa-alm.at',NULL);
INSERT INTO places VALUES(6,1,'Mirli','Ein 1792 erbautes Forsthaus mit atemberaubendem Blick über die grünen Hügel eines außerordentlich schönen Stückerls Wienerwald, keine 15 Minuten von der Wiener Stadtgrenze entfernt.','Heinratsberg 69','3011','Tullnerbach/Irenental','Österreich','0664/22231 31','Mi-So, Fei 11.30-24','www.mirli.at',NULL);
INSERT INTO places VALUES(7,1,'Araz','Das jüngste Top-Hotel Budapests, das Continental, befindet sich im früheren Jugendstil-Bad Hungäria, sein Restaurant Araz hat schon viele Preise eingeheimst. Gekocht wird eine französisch-ungarische Fusionsküche.','Dohány utca 42-44','2+36','Budapest','Ungarn','2+36/1/815 1100','Mo-So 7-23','www.araz.hu',NULL);
INSERT INTO places VALUES(8,6,'Quellenhof Luxury Resort Lazise','Umgeben von Oliven- und Pinienhainen, oberhalb des malerischen Städtchens, genießt man atemberaubende Ausblicke auf das Süd-Ostufer des Garda-sees.',NULL,NULL,'Lazise','Italien',NULL,NULL,'www.quellenhof-lazise.it','+');
