INSERT INTO books VALUES(1,12,'Fit & schlank mit Brot','Michaela Axt-Gadermann','Südwest Verlag','2025','176','ca. 21 Euro',NULL,'Das Buch von Ernährungsmedizinerin Michaela Axt-Gadermann und Brotsommelier Johannes Dackweiler erklärt, warum viele Brotsorten sehr gesund sind und welche gesundheitsförderlichen Wirkungen Getreide und seine Bestandteile auf Herzgesundheit, Arterkrankungen, Verdauungskreislauf und andere Gesundheitsaspekte haben. Es enthält Backrezepte für unterschiedliche Bedürfnisse, wie glutenfreie oder histaminarme Brote, sowie Ballaststoffe, Proteine und gesunde Fette. Das Buch bietet auch Tipps zur richtigen Auswahl von Brot und dessen Verwendung in der Ernährung.');
INSERT INTO books VALUES(4,13,'Il Milione - Die Wunder der Welt','Marco Polo','Manesse Verlag','2024','432','47,50 Euro','null','Marco Polo hat mit diesem Buch versucht, die Welt aus altfranzösischen und lateinischen Quellen zu übersetzen. Die Übersetzung trifft den Kern des Buches, da sie die Grenzen zwischen Bericht und Fabulierung verschwimmen lässt. Das Buch ist eine wertvolle Versuchung, die Leser für Schmunzeln und Verwunderung sorgt.');
INSERT INTO books VALUES(5,14,'Vegetarisch','Paul Ivić','DK Verlag',NULL,NULL,'42,50 €',NULL,'Rezeptbuch des österreichischen Sternekochs Paul Ivić, u.a. mit einem Rezept für eingelegten Ingwer (Gari).');
INSERT INTO books VALUES(6,22,'Die Mohnwirtin kocht','Rosemarie Neuwiesinger','Eigenverlag',NULL,NULL,'29 €',NULL,'Kochbuch der Mohnwirtin Rosemarie Neuwiesinger, u.a. mit dem Marillenknödel-Rezept.');
INSERT INTO recipes VALUES(5,12,'Topfen-Eiweißbrot','Brot','1 Laib','30 Minuten','Kerne, Kleie, Süßlupinenmehl, Leinsamenschrot und Flohsamenschalen mit Weinsteinbackpulver, Mehlgemisch, Eier, Olivenöl, Balsamicoessig oder Essig, Wasser, Salz','1. Kerne, Kleie, Süßlupinenmehl, Leinsamenschrot und Flohsamenschalen mit Weinsteinbackpulver, Mehlgemisch, Eier, Olivenöl, Balsamicoessig oder Essig, Wasser, Salz verrühren. 2. Die Masse mit Mehlgemisch gut vermengen und kräftig durchkneten. Einen Laib formen, der in einer kleinen Kastenform oder auf einem Backblech gebacken wird. Oberfläche anfeuchten und mit Saaten bestreuen. 3. Das Brot bei 180 °C (Umluft) backen. 4. Tipp: Dazu passt ein cremiger, mild gesäuerter Topfen, angekocht mit Gartenkräutern wie Schnittlauch, Dille sowie einem Schuss Zitronensaft.');
INSERT INTO recipes VALUES(6,12,'Leinsaat-Nuss-Brot','Brot','1 Laib','4 Stunden','Walnüsse, Sonnenblumenkerne, Leinsamen, Flohsamenschalen, Leinsamenmehl, Meersalz, Walnussöl, Rohrohrzucker, Wasser','1. Kastenform mit Backpapier auslegen. Walnüsse hacken. Mit den Sonnenblumenkernen, Leinsamen, Flohsamenschalen, Leinsamenmehl und Meerzsalz in einer Rührschüssel mit einem Schneebesen vermischen. 2. Öl, Zucker und 350 ml Wasser in mehreren Portionen mit den Quirlen eines Handrührgeräts unterrühren. Den Teig in Kastenform füllen, glatt streichen und zugedeckt 3 Stunden quellen lassen. 3. Den Backofen auf 180 °C (Ober-/Unterhitze) vorheizen. Das Brot mit Leinsamen bestreuen und im Ofen auf mittlerer Schiene 60-70 Minuten backen. 4. Das Brot aus dem Ofen nehmen und auf Kuchen gitter 10 Minuten abkühlen lassen. Dann aus der Form lösen und vollständig auskühlen lassen. Kühl und trocken gelagert, bleibt es bis zu 1 Woche saftig.');
INSERT INTO recipes VALUES(7,12,'Vollkornweckerl','Brot','8 Stück','ca. 12 Stunden (Übernacht)',replace('250 ml kaltes Wasser\n1 TL Kokosblütenzucker\n15 g frische Hefe\n300 g Dinkelvollkornmehl\n100 g Haferflocken, fein gemahlen\n50 g Leinsamen, geschrotet\n1 TL Salz\n2 EL Olivenöl\nSonnenblumenkerne, Kürbiskerne oder Sesam zum Bestreuen','\n',char(10)),replace('1. Am Vorabend das kalte Wasser mit Kokosblütenzucker mischen und die Hefe darin auflösen.\n2. In einer großen Schüssel Mehl, gemahlene Haferflocken, Leinsamen und Salz vermischen. Hefe-Wasser und Olivenöl hinzugeben und zu einem geschmeidigen, leicht klebrigen Teig kneten.\n3. Den Teig abgedeckt für mindestens 12 Stunden (über Nacht) im Kühlschrank ruhen lassen.\n4. Am nächsten Morgen den Teig aus dem Kühlschrank nehmen und 10-15 Minuten bei Raumtemperatur ruhen lassen. In 8 gleich große Portionen teilen und zu Brötchen formen.\n5. Den Ofen auf 220 °C (Ober-/Unterhitze) vorheizen. Brötchen auf ein Backblech legen und 20-30 Minuten gehen lassen.\n6. Optional: Brötchen mit Wasser bestreichen und mit Kernen/Sesam bestreuen.\n7. 20-25 Minuten backen bis sie goldbraun und knusprig sind. Auf einem Gitter auskühlen lassen.','\n',char(10)));
INSERT INTO recipes VALUES(10,15,'POPCORN','Snack','1-2 Kolben','20 Minuten','1-2 Kolben Popcornmais, Maiskeimöl, Salz','1. Löse die Körner mit den Fingern vom Maiskolben ab. Entferne kleine Pflanzenhärchen und -brösel. Alternativ: Kaufe fertig abgerebelte Popcornmaiskörner. 2. Gib 3 EL ÖL in einen geräumigen Topf. Streue die Maiskörner hinein, schwenke sie, sodass alle mit Öl bedeckt sind. 3. Erhitze den Topf, bis das Öl leicht zu blubbern beginnt, dann setze den Deckel auf. 4. Der Mais beginnt nach 2-3 Minuten zu „poppen”. Schüttle den Topf immer wie- der mal durch, ohne den Deckel zu öffnen. 5. Wird es still im Topf, sind alle Körner explodiert. 6. Hebe den Deckel vorsichtig ab. 7. Salze das Popcorn, leere es in eine Schüssel.');
INSERT INTO recipes VALUES(11,16,'VEGANE KNOBLAUCH-MAYO','Snack','5','10 Minuten','Abtropfwasser eines kleinen Glases Kichererbsen (ca 50 ml), YTL englischer Senf, 1 TL Zitronensaft, Ca. 200 ml Raps- oder Sonnenblumenöl, 1-2 Knoblauchzehen, Salz','Lege ein Sieb auf eine schmale Schüssel,schütte die Kichererbsen hinein und lasse sie gut abtropfen. Verwende die Kichererbsen z.B. für Salate oder Hummus. Schäle den Knoblauch, viertle ihn. Gib Senf, Knoblauch und Zitronensaft zum Kichererbsenwasser, mixe es mit einem Handmixgerät oder Stabmixer luftig auf. Jetzt brauchst du Hilfe: einer hält die Schüssel, einer gießt nach und nach Öl dazu und mixt es ein. Zuerst tropfenweise, dann in einem dünnen Strahl. Die Mayonnaise wird immer dicker und fester. Schmecke sie mit Salz und Zitronensaft ab.');
INSERT INTO recipes VALUES(12,17,'POPCORN','Snack','1-2 Kolben','20 Minuten','1-2 Kolben Popcornmais, Maiskeimöl, Salz','1. Löse die Körner mit den Fingern vom Maiskolben ab. Entferne kleine Pflanzenhärchen und -brösel. Alternativ: Kaufe fertig abgerebelte Popcornmaiskörner. 2. Gib 3 EL ÖL in einen geräumigen Topf. Streue die Maiskörner hinein, schwenke sie, sodass alle mit Öl bedeckt sind. 3. Erhitze den Topf, bis das Öl leicht zu blubbern beginnt, dann setze den Deckel auf. 4. Der Mais beginnt nach 2-3 Minuten zu „poppen”. Schüttle den Topf immer wie- der mal durch, ohne den Deckel zu öffnen. 5. Wird es still im Topf, sind alle Körner explodiert. 6. Hebe den Deckel vorsichtig ab. 7. Salze das Popcorn, leere es in eine Schüssel.');
INSERT INTO recipes VALUES(13,18,'VEGANE KNOBLAUCH-MAYO','Snack','5','10 Minuten','Abtropfwasser eines kleinen Glases Kichererbsen (ca 50 ml), YTL englischer Senf, 1 TL Zitronensaft, Ca. 200 ml Raps- oder Sonnenblumenöl, 1-2 Knoblauchzehen, Salz','Lege ein Sieb auf eine schmale Schüssel,schütte die Kichererbsen hinein und lasse sie gut abtropfen. Verwende die Kichererbsen z.B. für Salate oder Hummus. Schäle den Knoblauch, viertle ihn. Gib Senf, Knoblauch und Zitronensaft zum Kichererbsenwasser, mixe es mit einem Handmixgerät oder Stabmixer luftig auf. Jetzt brauchst du Hilfe: einer hält die Schüssel, einer gießt nach und nach Öl dazu und mixt es ein. Zuerst tropfenweise, dann in einem dünnen Strahl. Die Mayonnaise wird immer dicker und fester. Schmecke sie mit Salz und Zitronensaft ab.');
INSERT INTO recipes VALUES(14,19,'POPCORN','Snack',NULL,'20 Minuten','1-2 Kolben Popcornmais, Maiskeimöl, Salz','1. Löse die Körner mit den Fingern vom Maiskolben ab. Entferne kleine Pflanzenhärchen und -brösel. Alternativ: Kaufe fertig abgerebelte Popcornmaiskörner. 2. Gib 3 EL ÖL in einen geräumigen Topf. Streue die Maiskörner hinein, schwenke sie, sodass alle mit Öl bedeckt sind. 3. Erhitze den Topf, bis das Öl leicht zu blubbern beginnt, dann setze den Deckel auf. 4. Der Mais beginnt nach 2-3 Minuten zu „poppen”. Schüttle den Topf immer wie- der mal durch, ohne den Deckel zu öffnen. 5. Wird es still im Topf, sind alle Körner explodiert. 6. Hebe den Deckel vorsichtig ab. 7. Salze das Popcorn, leere es in eine Schüssel.');
INSERT INTO recipes VALUES(15,20,'VEGANE KNOBLAUCH-MAYO','Snack','5','10 Minuten','Abtropfwasser eines kleinen Glases Kichererbsen (ca 50 ml), ½ TL englischer Senf, 1 TL Zitronensaft, Ca. 200 ml Raps- oder Sonnenblumenöl, 1-2 Knoblauchzehen, Salz','Lege ein Sieb auf eine schmale Schüssel,schütte die Kichererbsen hinein und lasse sie gut abtropfen. Verwende die Kichererbsen z.B. für Salate oder Hummus. Schäle den Knoblauch, viertle ihn. Gib Senf, Knoblauch und Zitronensaft zum Kichererbsenwasser, mixe es mit einem Handmixgerät oder Stabmixer luftig auf. Jetzt brauchst du Hilfe: einer hält die Schüssel, einer gießt nach und nach Öl dazu und mixt es ein. Zuerst tropfenweise, dann in einem dünnen Strahl. Die Mayonnaise wird immer dicker und fester. Schmecke sie mit Salz und Zitronensaft ab.');
INSERT INTO recipes VALUES(16,14,'Eingelegter Ingwer (Gari)','Eingemachtes',NULL,NULL,'100 g Ingwer, 120 ml Reisessig (oder anderer heller Essig), 90 g Zucker, 25 g Salz','1. Ingwer schälen, in möglichst feine Scheiben schneiden und 1 Minute kochen. Abseihen und in ein Einmachglas geben. 2. Reisessig mit Zucker und Salz aufkochen und rühren, bis sich der Zucker aufgelöst hat. 3. Über den Ingwer gießen und verschließen. 4. Vor dem Servieren 1 Tag stehen lassen. Gekühlt und verschlossen bis zu 4 Wochen haltbar.');
INSERT INTO recipes VALUES(17,14,'Schaumröllchen','Gebäck',NULL,'1 Stunde','1 Packung Blätterteig, 1 Becher Schlagobers, 1 Packerl Vanillezucker, Staubzucker, Butter zum Einstreichen','1. Backrohr auf 180 °C vorheizen. Förmchen mit Butter einstreichen. 2. Noch kalten Blätterteig entrollen und quer in 1 cm breite Streifen schneiden. 3. Teigstreifen leicht überlappend auf die Förmchen wickeln, auf ein mit Backpapier ausgelegtes Backblech legen. 4. Mit Heißluft 15-20 Minuten backen. Aus dem Ofen nehmen, überkühlen lassen und behutsam mit leichter Drehung von den Formen ziehen. 5. Schlagobers mit Vanillezucker steif schlagen, in einen Dressiersack füllen und in die Röllchen spritzen. 6. Mit Staubzucker bestreuen und sofort servieren.');
INSERT INTO recipes VALUES(18,21,'Ofengemüse (Süßkartoffel und Kohlsprossen)','Beilage','1 Portion','15 Minuten','Süßkartoffel, Kohlsprossen, Rosmarin, Olivenöl, Salz','Ziehe Süßkartoffeln halbieren, Kohlsprossen waschen, Rosmarin entfernen, Kohlsprossen halbieren. Verteile das Gemüse auf einem Backblech, bestreut mit Olivenöl und Salz. Backe 15-20 Minuten in der Heißluft. Nimm es heraus, iss es heiß, am besten mit einem Sauerrahm-Dip.');
INSERT INTO recipes VALUES(21,22,'Marillenknödel mit Mohnbröseln und Marillenröster','Mehlspeise','12 Knödel','1,5 Stunden','Teig: ½ kg gekochte, gepresste, kalte Erdäpfel (z.B. Sorte Ditta), 1 Ei, 1 EL weiche Butter, 250 g griffiges Mehl, Prise Salz, 12 Marillen | Mohnbrösel: 70 g Semmelbrösel, 1 EL Feinkristallzucker, 70 g Graumohn (gequetscht), 50 g Butter | Marillenröster: 1 kg entkernte Marillen, etwas Wasser, etwas Zitronensaft, 3 EL Zucker, 1 TL Vanillezucker','1. Erdäpfel kochen, noch heiß schälen, auskühlen lassen. Ausgekühlt durch eine Erdäpfelpresse drücken, mit Ei, Butter, Mehl und Salz vermischen und zu einem seidigen Teig kneten. 2. Teig in 12 Stücke teilen, flachdrücken, je eine Marille drauflegen, Teig rundherum andrücken und rund formen. 3. Knödel in kochendes Salzwasser einlegen und ca. 15 Minuten leicht kochen. Wenn sie schwimmen, sind sie fertig. 4. Brösel und Graumohn in Butter und Zucker anrösten, Knödel darin wälzen, mit Staubzucker bestreuen. 5. Marillenröster: entkernte Marillen mit Wasser, Zucker, Vanillezucker und Zitronensaft aufkochen, abkühlen lassen. Mit Röster anrichten.');
